import type { BibleBook } from '../bibleData';

export const romansBook: BibleBook = {
  id: 'romans',
  name: 'Romanos',
  englishName: 'Romans',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'Paul, a servant of Jesus Christ, called to be an apostle, separated unto the gospel of God,', pt: 'Paulo, servo de Jesus Cristo, chamado para apóstolo, separado para o evangelho de Deus,' },
      { v: 2, en: 'Which he had promised afore by his prophets in the holy scriptures,', pt: 'que ele havia prometido antes pelos seus profetas nas sagradas escrituras,' },
      { v: 3, en: 'Concerning his Son Jesus Christ our Lord, which was made of the seed of David according to the flesh;', pt: 'acerca de seu Filho, que nasceu da semente de Davi segundo a carne,' },
      { v: 4, en: 'And declared to be the Son of God with power, according to the spirit of holiness, by the resurrection from the dead:', pt: 'e foi declarado Filho de Deus com poder, segundo o espírito de santidade, pela ressurreição dos mortos, Jesus Cristo nosso Senhor,' },
      { v: 5, en: 'By whom we have received grace and apostleship, for obedience to the faith among all nations, for his name:', pt: 'pelo qual recebemos a graça e o apostolado para a obediência da fé entre todos os gentios, por amor do seu nome;' },
      { v: 6, en: 'Among whom are ye also the called of Jesus Christ:', pt: 'entre os quais sois também vós chamados de Jesus Cristo;' },
      { v: 7, en: 'To all that be in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father, and the Lord Jesus Christ.', pt: 'a todos os que estão em Roma, amados de Deus, chamados para santos: graça a vós outros e paz da parte de Deus nosso Pai e do Senhor Jesus Cristo.' },
      { v: 8, en: 'First, I thank my God through Jesus Christ for you all, that your faith is spoken of throughout the whole world.', pt: 'Primeiramente, dou graças ao meu Deus por Jesus Cristo, a respeito de todos vós, porque a vossa fé é anunciada em todo o mundo.' },
      { v: 9, en: 'For God is my witness, whom I serve with my spirit in the gospel of his Son, that without ceasing I make mention of you always in my prayers;', pt: 'Porque Deus, a quem sirvo em meu espírito no evangelho de seu Filho, me é testemunha de como incessantemente faço menção de vós,' },
      { v: 10, en: 'Making request, if by any means now at length I might have a prosperous journey by the will of God to come unto you.', pt: 'pedindo sempre em minhas orações que, afinal, de algum modo, me seja prosperado o caminho, pela vontade de Deus, para ir a vós outros.' },
      { v: 11, en: 'For I long to see you, that I may impart unto you some spiritual gift, to the end ye may be established;', pt: 'Porque muito desejo ver-vos, para vos comunicar algum dom espiritual, a fim de que sejais confirmados;' },
      { v: 12, en: 'That is, that I may be comforted together with you by the mutual faith both of you and me.', pt: 'isto é, para ser mutuamente consolado entre vós pela nossa comum fé, tanto a vossa como a minha.' },
      { v: 13, en: 'Now I would not have you ignorant, brethren, that oftentimes I purposed to come unto you, (but was let hitherto,) that I might have some fruit among you also, even as among other Gentiles.', pt: 'Não quero, porém, irmãos, que ignoreis que muitas vezes me propus ir ter convosco (mas até agora tenho sido impedido), para colher algum fruto também entre vós, como entre os demais gentios.' },
      { v: 14, en: 'I am debtor both to the Greeks, and to the Barbarians; both to the wise, and to the unwise.', pt: 'Sou devedor tanto aos gregos como aos bárbaros, tanto aos sábios como aos ignorantes.' },
      { v: 15, en: 'So, as much as in me is, I am ready to preach the gospel to you that are at Rome also.', pt: 'Assim, quanto de mim depende, estou pronto para anunciar o evangelho também a vós outros que estais em Roma.' },
      { v: 16, en: 'For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek.', pt: 'Porque não me envergonho do evangelho de Cristo, pois é o poder de Deus para a salvação de todo aquele que crê; primeiro do judeu, e também do grego.' },
      { v: 17, en: 'For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith.', pt: 'Porque nele a justiça de Deus se revela de fé em fé, como está escrito: O justo viverá pela fé.' },
      { v: 18, en: 'For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth in unrighteousness;', pt: 'Porque do céu se revela a ira de Deus contra toda a impiedade e injustiça dos homens que detêm a verdade em injustiça.' },
      { v: 19, en: 'Because that which may be known of God is manifest in them; for God hath shewed it unto them.', pt: 'Porquanto o que de Deus se pode conhecer é manifesto entre eles, porque Deus lho manifestou.' },
      { v: 20, en: 'For the invisible things of him from the creation of the world are clearly seen, being understood by the things that are made, even his eternal power and Godhead; so that they are without excuse:', pt: 'Porque os atributos invisíveis de Deus, assim o seu eterno poder como a sua divindade, claramente se reconhecem, desde a criação do mundo, sendo percebidos pelas coisas que foram feitas. Tais homens são por isso inexcusáveis;' },
      { v: 21, en: 'Because that, when they knew God, they glorified him not as God, neither were thankful; but became vain in their imaginations, and their foolish heart was darkened.', pt: 'porquanto, tendo conhecido a Deus, não o glorificaram como Deus, nem lhe renderam graças, antes em seus próprios raciocínios se tornaram nulos, obscurecendo-se-lhes o coração insensato.' },
      { v: 22, en: 'Professing themselves to be wise, they became fools,', pt: 'Dizendo-se sábios, tornaram-se loucos,' },
      { v: 23, en: 'And changed the glory of the uncorruptible God into an image made like to corruptible man, and to birds, and fourfooted beasts, and creeping things.', pt: 'e mudaram a glória do Deus incorruptível em semelhança da imagem de homem corruptível, bem como de aves, quadrúpedes e répteis.' },
      { v: 24, en: 'Wherefore God also gave them up to uncleanness through the lusts of their own hearts, to dishonour their own bodies between themselves:', pt: 'Por isso, Deus os entregou à imundícia, pelas concupiscências de seus próprios corações, de modo que desonraram os seus corpos entre si mesmos;' },
      { v: 25, en: 'Who changed the truth of God into a lie, and worshipped and served the creature more than the Creator, who is blessed for ever. Amen.', pt: 'eles, que mudaram a verdade de Deus em mentira, e honraram e serviram a criatura em lugar do Criador, que é bendito eternamente. Amém.' },
      { v: 26, en: 'For this cause God gave them up unto vile affections: for even their women did change the natural use into that which is against nature:', pt: 'Por isso, Deus os entregou a paixões infames; porque até as suas mulheres mudaram o uso natural no que é contrário à natureza.' },
      { v: 27, en: 'And likewise also the men, leaving the natural use of the woman, burned in their lust one toward another; men with men working that which is unseemly, and receiving in themselves that recompence of their error which was meet.', pt: 'Da mesma forma, os homens também, deixando o uso natural da mulher, se inflamaram em desejos uns para com os outros, cometendo torpeza, homens com homens, e recebendo em si mesmos a devida recompensa do seu erro.' },
      { v: 28, en: 'And even as they did not like to retain God in their knowledge, God gave them over to a reprobate mind, to do those things which are not convenient;', pt: 'E como não se importaram de ter a Deus em seu pleno conhecimento, Deus os entregou a um sentido pervertido, para fazerem coisas que não convêm;' },
      { v: 29, en: 'Being filled with all unrighteousness, fornication, wickedness, covetousness, maliciousness; full of envy, murder, debate, deceit, malignity; whisperers,', pt: 'estando cheios de toda injustiça, malícia, cobiça, maldade; cheios de inveja, homicídio, contenda, dolo, malignidade; sendo murmuradores,' },
      { v: 30, en: 'Backbiters, haters of God, despiteful, proud, boasters, inventors of evil things, disobedient to parents,', pt: 'difamadores, aborrecedores de Deus, insolentes, soberbos, arrogantes, inventores de males, desobedientes aos pais,' },
      { v: 31, en: 'Without understanding, covenantbreakers, without natural affection, implacable, unmerciful:', pt: 'insensatos, desleais, sem afeição natural, implacáveis, sem misericórdia;' },
      { v: 32, en: 'Who knowing the judgment of God, that they which commit such things are worthy of death, not only do the same, but have pleasure in them that do them.', pt: 'esses que, conhecendo o decreto de Deus, que tais crimes são dignos de morte, não somente os praticam, mas também aprovam os que os praticam.' },
    ],
    2: [
      { v: 1, en: 'Therefore thou art inexcusable, O man, whosoever thou art that judgest: for wherein thou judgest another, thou condemnest thyself; for thou that judgest doest the same things.', pt: 'Portanto, és inexcusável, ó homem, quem quer que sejas, quando julgas; pois, ao julgares a outro, a ti mesmo te condenas, porque tu, que julgas, praticas as mesmas coisas.' },
      { v: 2, en: 'But we are sure that the judgment of God is according to truth against them which commit such things.', pt: 'Mas sabemos que o juízo de Deus é segundo a verdade contra os que praticam tais coisas.' },
      { v: 3, en: 'And thinkest thou this, O man, that judgest them which do such things, and doest the same, that thou shalt escape the judgment of God?', pt: 'E pensas tu, ó homem, que julgas os que praticam tais coisas e fazes o mesmo, que escaparás ao juízo de Deus?' },
      { v: 4, en: 'Or despisest thou the riches of his goodness and forbearance and longsuffering; not knowing that the goodness of God leadeth thee to repentance?', pt: 'Ou desprezas as riquezas da sua bondade, paciência e longanimidade, ignorando que a bondade de Deus te leva ao arrependimento?' },
      { v: 5, en: 'But after thy hardness and impenitent heart treasurest up unto thyself wrath against the day of wrath and revelation of the righteous judgment of God;', pt: 'Tu, porém, pela tua dureza e pelo teu coração impenitente, acumulas para ti mesmo ira para o dia da ira e da revelação do justo juízo de Deus,' },
      { v: 6, en: 'Who will render to every man according to his deeds:', pt: 'o qual retribuirá a cada um segundo as suas obras:' },
      { v: 7, en: 'To them who by patient continuance in well doing seek for glory and honour and immortality, eternal life:', pt: 'a vida eterna aos que, com perseverança em fazer bem, procuram glória, honra e imortalidade;' },
      { v: 8, en: 'But unto them that are contentious, and do not obey the truth, but obey unrighteousness, indignation and wrath,', pt: 'mas ira e furor aos que são contenciosos e não obedecem à verdade, antes obedecem à injustiça;' },
      { v: 9, en: 'Tribulation and anguish, upon every soul of man that doeth evil, of the Jew first, and also of the Gentile;', pt: 'tribulação e angústia sobre toda alma de homem que pratica o mal, primeiro do judeu, e também do grego;' },
      { v: 10, en: 'But glory, honour, and peace, to every man that worketh good, to the Jew first, and also to the Gentile:', pt: 'mas glória, honra e paz a todo aquele que pratica o bem, primeiro ao judeu, e também ao grego;' },
      { v: 11, en: 'For there is no respect of persons with God.', pt: 'porque para com Deus não há acepção de pessoas.' },
      { v: 12, en: 'For as many as have sinned without law shall also perish without law: and as many as have sinned in the law shall be judged by the law;', pt: 'Porque todos os que pecaram sem lei também sem lei perecerão; e todos os que pecaram debaixo da lei serão julgados pela lei.' },
      { v: 13, en: 'For not the hearers of the law are just before God, but the doers of the law shall be justified.', pt: 'Porque não são justos diante de Deus os que ouvem a lei, mas os que a praticam serão justificados.' },
      { v: 14, en: 'For when the Gentiles, which have not the law, do by nature the things contained in the law, these, having not the law, are a law unto themselves:', pt: 'Porque quando os gentios, que não têm lei, fazem por natureza as coisas que são da lei, esses, não tendo lei, são lei para si mesmos;' },
      { v: 15, en: 'Which shew the work of the law written in their hearts, their conscience also bearing witness, and their thoughts the mean while accusing or else excusing one another;)', pt: 'como os que mostram ser a obra da lei gravada em seus corações, testemunhando-o também a sua consciência, e os seus pensamentos mutuamente acusando-os ou escusando-os;' },
      { v: 16, en: 'In the day when God shall judge the secrets of men by Jesus Christ according to my gospel.', pt: 'no dia em que Deus, por Jesus Cristo, julgar os segredos dos homens, conforme o meu evangelho.' },
      { v: 17, en: 'Behold, thou art called a Jew, and restest in the law, and makest thy boast of God,', pt: 'Eis que tu te cognominas judeu, e repousas na lei, e te glorias em Deus,' },
      { v: 18, en: 'And knowest his will, and approvest the things that are more excellent, being instructed out of the law;', pt: 'e conheces a sua vontade, e aprovas as coisas excelentes, sendo instruído pela lei;' },
      { v: 19, en: 'And art confident that thou thyself art a guide of the blind, a light of them which are in darkness,', pt: 'e estás persuadido de que és guia dos cegos, luz dos que estão em trevas,' },
      { v: 20, en: 'An instructor of the foolish, a teacher of babes, which hast the form of knowledge and of the truth in the law.', pt: 'instrutor dos insensatos, mestre de crianças, tendo na lei a forma da ciência e da verdade.' },
      { v: 21, en: 'Thou therefore which teachest another, teachest thou not thyself? thou that preachest a man should not steal, dost thou steal?', pt: 'Tu, pois, que ensinas a outro, não te ensinas a ti mesmo? Tu, que pregas que não se deve furtar, furtas?' },
      { v: 22, en: 'Thou that sayest a man should not commit adultery, dost thou commit adultery? thou that abhorrest idols, dost thou commit sacrilege?', pt: 'Tu, que dizes que não se deve adulterar, adulteras? Tu, que abominas os ídolos, praticas sacrilégio?' },
      { v: 23, en: 'Thou that makest thy boast of the law, through breaking the law dishonourest thou God?', pt: 'Tu, que te glorias na lei, desonras a Deus pela transgressão da lei?' },
      { v: 24, en: 'For the name of God is blasphemed among the Gentiles through you, as it is written.', pt: 'Porque o nome de Deus é blasfemado entre os gentios por vossa causa, como está escrito.' },
      { v: 25, en: 'For circumcision verily profiteth, if thou keep the law: but if thou be a breaker of the law, thy circumcision is made uncircumcision.', pt: 'Porque a circuncisão aproveita, se guardas a lei; mas, se és transgressor da lei, a tua circuncisão se torna incircuncisão.' },
      { v: 26, en: 'Therefore if the uncircumcision keep the righteousness of the law, shall not his uncircumcision be counted for circumcision?', pt: 'Se, portanto, o incircunciso guardar os preceitos da lei, não será a sua incircuncisão contada como circuncisão?' },
      { v: 27, en: 'And shall not uncircumcision which is by nature, if it fulfil the law, judge thee, who by the letter and circumcision dost transgress the law?', pt: 'E o incircunciso de nascença, que cumpre a lei, não te julgará a ti, que, com a letra e a circuncisão, és transgressor da lei?' },
      { v: 28, en: 'For he is not a Jew, which is one outwardly; neither is that circumcision, which is outward in the flesh:', pt: 'Porque não é judeu o que o é exteriormente, nem é circuncisão a que o é exteriormente na carne;' },
      { v: 29, en: 'But he is a Jew, which is one inwardly; and circumcision is that of the heart, in the spirit, and not in the letter; whose praise is not of men, but of God.', pt: 'mas é judeu o que o é interiormente, e circuncisão é a do coração, no espírito, não na letra; cujo louvor não vem dos homens, mas de Deus.' },
    ],
    3: [
      { v: 1, en: 'What advantage then hath the Jew? or what profit is there of circumcision?', pt: 'Qual é, pois, a vantagem do judeu? ou qual é o proveito da circuncisão?' },
      { v: 2, en: 'Much every way: chiefly, because that unto them were committed the oracles of God.', pt: 'Muito em todos os sentidos. Primeiro, em verdade, porque a eles foram confiados os oráculos de Deus.' },
      { v: 3, en: 'For what if some did not believe? shall their unbelief make the faith of God without effect?', pt: 'Pois que? Se alguns foram infiéis, a sua incredulidade tornará vão o fiel de Deus?' },
      { v: 4, en: 'God forbid: yea, let God be true, but every man a liar; as it is written, That thou mightest be justified in thy sayings, and mightest overcome when thou art judged.', pt: 'De modo nenhum; antes, seja Deus verdadeiro, e todo homem mentiroso; como está escrito: Para que sejas justificado nas tuas palavras, e vences quando fores julgado.' },
      { v: 5, en: 'But if our unrighteousness commend the righteousness of God, what shall we say? Is God unrighteous who taketh vengeance? (I speak as a man)', pt: 'Mas se a nossa injustiça realça a justiça de Deus, que diremos? Porventura Deus é injusto quando inflinge a sua ira? (falo como homem).' },
      { v: 6, en: 'God forbid: for then how shall God judge the world?', pt: 'De modo nenhum; de outro modo, como julgará Deus o mundo?' },
      { v: 7, en: 'For if the truth of God hath more abounded through my lie unto his glory; why yet am I also judged as a sinner?', pt: 'Mas se a verdade de Deus abundou mais para sua glória por meio da minha mentira, por que ainda sou julgado como pecador?' },
      { v: 8, en: 'And not rather, (as we be slanderously reported, and as some affirm that we say,) Let us do evil, that good may come? whose damnation is just.', pt: 'E por que não fazer mal para que venha o bem? como alguns, difamando-nos, afirmam que nós dizemos. A condenação de tais pessoas é justa.' },
      { v: 9, en: 'What then? are we better than they? No, in no wise: for we have before proved both Jews and Gentiles, that they are all under sin;', pt: 'Que concluiremos, pois? Somos nós superiores? De forma nenhuma; porque já demonstramos que tanto judeus como gregos estão todos debaixo do pecado,' },
      { v: 10, en: 'As it is written, There is none righteous, no, not one:', pt: 'como está escrito: Não há justo, nem um sequer;' },
      { v: 11, en: 'There is none that understandeth, there is none that seeketh after God.', pt: 'não há ninguém que entenda; não há ninguém que busque a Deus.' },
      { v: 12, en: 'They are all gone out of the way, they are together become unprofitable; there is none that doeth good, no, not one.', pt: 'Todos se desviaram, e juntamente se tornaram inúteis; não há quem faça o bem, não há nem um.' },
      { v: 13, en: 'Their throat is an open sepulchre; with their tongues they have used deceit; the poison of asps is under their lips:', pt: 'A sua garganta é um sepulcro aberto; com as suas línguas tratam enganosamente; o veneno das áspides está debaixo dos seus lábios;' },
      { v: 14, en: 'Whose mouth is full of cursing and bitterness:', pt: 'a sua boca está cheia de maldição e amargura.' },
      { v: 15, en: 'Their feet are swift to shed blood:', pt: 'Os seus pés são velozes para derramar sangue;' },
      { v: 16, en: 'Destruction and misery are in their ways:', pt: 'em seus caminhos há destruição e miséria;' },
      { v: 17, en: 'And the way of peace have they not known:', pt: 'e não conheceram o caminho da paz.' },
      { v: 18, en: 'There is no fear of God before their eyes.', pt: 'Não há temor de Deus diante dos seus olhos.' },
      { v: 19, en: 'Now we know that what things soever the law saith, it saith to them who are under the law: that every mouth may be stopped, and all the world may become guilty before God.', pt: 'Ora, sabemos que tudo o que a lei diz, diz àqueles que estão debaixo da lei, para que toda boca esteja fechada e todo o mundo seja culpável diante de Deus.' },
      { v: 20, en: 'Therefore by the deeds of the law there shall no flesh be justified in his sight: for by the law is the knowledge of sin.', pt: 'Pois que pelas obras da lei nenhuma carne será justificada diante dele; porque pelo meio da lei vem o conhecimento do pecado.' },
      { v: 21, en: 'But now the righteousness of God without the law is manifested, being witnessed by the law and the prophets;', pt: 'Mas agora, independentemente da lei, a justiça de Deus se manifestou, sendo testificada pela lei e pelos profetas;' },
      { v: 22, en: 'Even the righteousness of God which is by faith of Jesus Christ unto all and upon all them that believe: for there is no difference:', pt: 'a saber, a justiça de Deus pela fé em Jesus Cristo, para todos os que creem. Porque não há distinção;' },
      { v: 23, en: 'For all have sinned, and come short of the glory of God;', pt: 'pois todos pecaram e destituídos estão da glória de Deus;' },
      { v: 24, en: 'Being justified freely by his grace through the redemption that is in Christ Jesus:', pt: 'sendo justificados gratuitamente pela sua graça, pela redenção que há em Cristo Jesus,' },
      { v: 25, en: 'Whom God hath set forth to be a propitiation through faith in his blood, to declare his righteousness for the remission of sins that are past, through the forbearance of God;', pt: 'a quem Deus propôs como propiciação mediante a fé no seu sangue, para demonstrar a sua justiça por causa da passagem dos pecados anteriores,' },
      { v: 26, en: 'To declare, I say, at this time his righteousness: that he might be just, and the justifier of him which believeth in Jesus.', pt: 'na tolerância de Deus; para demonstrar a sua justiça no tempo presente, para ser ele justo e o justificador daquele que tem fé em Jesus.' },
      { v: 27, en: 'Where is boasting then? It is excluded. By what law? of works? Nay: but by the law of faith.', pt: 'Onde está, pois, a jactância? Ficou excluída. Por que lei? Das obras? Não; mas pela lei da fé.' },
      { v: 28, en: 'Therefore we conclude that a man is justified by faith without the deeds of the law.', pt: 'Concluímos, pois, que o homem é justificado pela fé, independentemente das obras da lei.' },
      { v: 29, en: 'Is he the God of the Jews only? is he not also of the Gentiles? Yes, of the Gentiles also:', pt: 'Ou será Deus somente Deus dos judeus? Não o é também dos gentios? Sim, também dos gentios;' },
      { v: 30, en: 'Seeing it is one God, which shall justify the circumcision by faith, and uncircumcision through faith.', pt: 'pois é um só Deus, que há de justificar pela fé os da circuncisão, e igualmente pela fé os da incircuncisão.' },
      { v: 31, en: 'Do we then make void the law through faith? God forbid: yea, we establish the law.', pt: 'Anulamos, pois, a lei pela fé? De modo nenhum! Antes, confirmamos a lei.' },
    ],
    4: [
      { v: 1, en: 'What shall we say then that Abraham our father, as pertaining to the flesh, hath found?', pt: 'Que diremos, pois, que Abraão, nosso pai segundo a carne, alcançou?' },
      { v: 2, en: 'For if Abraham were justified by works, he hath whereof to glory; but not before God.', pt: 'Porque se Abraão foi justificado pelas obras, tem de que se gloriar, mas não diante de Deus.' },
      { v: 3, en: 'For what saith the scripture? Abraham believed God, and it was counted unto him for righteousness.', pt: 'Porque diz a Escritura: Creu Abraão a Deus, e isso lhe foi imputado como justiça.' },
      { v: 4, en: 'Now to him that worketh is the reward not reckoned of grace, but of debt.', pt: 'Ora, ao que obra, o salário não é imputado segundo a graça, mas segundo a dívida.' },
      { v: 5, en: 'But to him that worketh not, but believeth on him that justifieth the ungodly, his faith is counted for righteousness.', pt: 'Ao que, porém, não obra, mas crê naquele que justifica o ímpio, a sua fé lhe é imputada como justiça.' },
      { v: 6, en: 'Even as David also describeth the blessedness of the man, unto whom God imputeth righteousness without works,', pt: 'Como também Davi descreve a bem-aventurança do homem a quem Deus imputa justiça sem obras:' },
      { v: 7, en: 'Saying, Blessed are they whose iniquities are forgiven, and whose sins are covered.', pt: 'Bem-aventurados aqueles cujas iniqüidades são perdoadas e cujos pecados são cobertos.' },
      { v: 8, en: 'Blessed is the man to whom the Lord will not impute sin.', pt: 'Bem-aventurado o homem a quem o Senhor não imputará o pecado.' },
      { v: 9, en: 'Cometh this blessedness then upon the circumcision only, or upon the uncircumcision also? for we say that faith was reckoned to Abraham for righteousness.', pt: 'Vem esta bem-aventurança somente sobre os circuncidados ou também sobre os incircuncisos? Porque dizemos que a Abraão a fé lhe foi imputada como justiça.' },
      { v: 10, en: 'How was it then reckoned? when he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision.', pt: 'Como, pois, lhe foi imputada? Sendo ele circuncidado ou incircunciso? Não sendo circuncidado, mas incircunciso.' },
      { v: 11, en: 'And he received the sign of circumcision, a seal of the righteousness of the faith which he had yet being uncircumcised: that he might be the father of all them that believe, though they be not circumcised; that righteousness might be imputed unto them also:', pt: 'E recebeu o sinal da circuncisão como selo da justiça da fé que tivera sendo ainda incircunciso; para ser pai de todos os que creem sem circuncisão, a fim de que a justiça lhes seja igualmente imputada;' },
      { v: 12, en: 'And the father of circumcision to them who are not of the circumcision only, but who also walk in the steps of that faith of our father Abraham, which he had being yet uncircumcised.', pt: 'e para ser pai da circuncisão aos que não são somente da circuncisão, mas também seguem as pisadas da fé de nosso pai Abraão, que ele tinha quando ainda era incircunciso.' },
      { v: 13, en: 'For the promise, that he should be the heir of the world, was not to Abraham, or to his seed, through the law, but through the righteousness of faith.', pt: 'Porque a promessa de que seria herdeiro do mundo não veio a Abraão, ou à sua descendência, pela lei, mas pela justiça da fé.' },
      { v: 14, en: 'For if they which are of the law be heirs, faith is made void, and the promise made of none effect:', pt: 'Porque se os que são da lei são os herdeiros, a fé é vã e a promessa é de nenhum efeito.' },
      { v: 15, en: 'Because the law worketh wrath: for where no law is, there is no transgression.', pt: 'Porque a lei produz ira; mas onde não há lei, também não há transgressão.' },
      { v: 16, en: 'Therefore it is of faith, that it might be by grace; to the end the promise might be sure to all the seed; not to that only which is of the law, but to that also which is of the faith of Abraham; who is the father of us all,', pt: 'Por isso é pela fé, para que seja segundo a graça, a fim de que a promessa seja firme para toda a descendência; não somente para o que é da lei, mas também para o que é da fé de Abraão, o qual é pai de todos nós,' },
      { v: 17, en: 'As it is written, I have made thee a father of many nations,) before him whom he believed, even God, who quickeneth the dead, and calleth those things which be not as though they were.', pt: 'como está escrito: Constituí-te pai de muitas nações; diante de Deus, em quem creu, o qual vivifica os mortos e chama as coisas que não são como se fossem.' },
      { v: 18, en: 'Who against hope believed in hope, that he might become the father of many nations, according to that which was spoken, So shall thy seed be.', pt: 'O qual, além da esperança, creu em esperança, para se tornar pai de muitas nações, segundo o que lhe foi dito: Assim será a tua descendência.' },
      { v: 19, en: 'And being not weak in faith, he considered not his own body now dead, when he was about an hundred years old, neither yet the deadness of Sara\'s womb:', pt: 'E não sendo fraco na fé, não considerou o seu próprio corpo, já amortecido, pois já tinha quase cem anos, nem a amortecência do ventre de Sara;' },
      { v: 20, en: 'He staggered not at the promise of God through unbelief; but was strong in faith, giving glory to God;', pt: 'e não duvidou da promessa de Deus por incredulidade, antes foi fortalecido na fé, dando glória a Deus,' },
      { v: 21, en: 'And being fully persuaded that, what he had promised, he was able also to perform.', pt: 'e estando plenamente persuadido de que o que havia prometido era também poderoso para cumprir.' },
      { v: 22, en: 'And therefore it was imputed to him for righteousness.', pt: 'Por isso também isso lhe foi imputado como justiça.' },
      { v: 23, en: 'Now it was not written for his sake alone, that it was imputed to him;', pt: 'Ora, não foi escrito somente por causa dele que lhe foi imputada a justiça,' },
      { v: 24, en: 'But for us also, to whom it shall be imputed, if we believe on him that raised up Jesus our Lord from the dead;', pt: 'mas também por causa de nós, a quem ela há de ser imputada, nós que cremos naquele que ressuscitou dentre os mortos a Jesus, nosso Senhor,' },
      { v: 25, en: 'Who was delivered for our offences, and was raised again for our justification.', pt: 'o qual foi entregue por causa das nossas transgressões e ressuscitou para a nossa justificação.' },
    ],
    5: [
      { v: 1, en: 'Therefore being justified by faith, we have peace with God through our Lord Jesus Christ:', pt: 'Justificados, pois, pela fé, temos paz com Deus por nosso Senhor Jesus Cristo;' },
      { v: 2, en: 'By whom also we have access by faith into this grace wherein we stand, and rejoice in hope of the glory of God.', pt: 'pelo qual também temos entrada pela fé a esta graça na qual estamos firmes, e nos gloriamos na esperança da glória de Deus.' },
      { v: 3, en: 'And not only so, but we glory in tribulations also: knowing that tribulation worketh patience;', pt: 'E não somente isso, mas também nos gloriamos nas tribulações; sabendo que a tribulação produz paciência,' },
      { v: 4, en: 'And patience, experience; and experience, hope:', pt: 'e a paciência, experiência, e a experiência, esperança.' },
      { v: 5, en: 'And hope maketh not ashamed; because the love of God is shed abroad in our hearts by the Holy Ghost which is given unto us.', pt: 'E a esperança não envergonha, porque o amor de Deus está derramado em nossos corações pelo Espírito Santo que nos foi dado.' },
      { v: 6, en: 'For when we were yet without strength, in due time Christ died for the ungodly.', pt: 'Porque Cristo, quando ainda éramos fracos, morreu a seu tempo pelos ímpios.' },
      { v: 7, en: 'For scarcely for a righteous man will one die: yet peradventure for a good man some would even dare to die.', pt: 'Porque dificilmente alguém morreria por um justo; mas talvez pelo bom alguém se atrevesse a morrer.' },
      { v: 8, en: 'But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us.', pt: 'Mas Deus prova o seu amor para conosco, em que Cristo morreu por nós, sendo nós ainda pecadores.' },
      { v: 9, en: 'Much more then, being now justified by his blood, we shall be saved from wrath through him.', pt: 'Logo, muito mais agora, tendo sido justificados pelo seu sangue, seremos por ele salvos da ira.' },
      { v: 10, en: 'For if, when we were enemies, we were reconciled to God by the death of his Son, much more, being reconciled, we shall be saved by his life.', pt: 'Porque se, sendo inimigos, fomos reconciliados com Deus pela morte de seu Filho, muito mais, tendo sido reconciliados, seremos salvos pela sua vida.' },
      { v: 11, en: 'And not only so, but we also joy in God through our Lord Jesus Christ, by whom we have now received the atonement.', pt: 'E não só isso, mas também nos gloriamos em Deus por nosso Senhor Jesus Cristo, pelo qual recebemos agora a reconciliação.' },
      { v: 12, en: 'Wherefore, as by one man sin entered into the world, and death by sin; and so death passed upon all men, for that all have sinned:', pt: 'Portanto, como por um só homem entrou o pecado no mundo, e pelo pecado a morte, assim também a morte se estendeu a todos os homens, porque todos pecaram.' },
      { v: 13, en: 'For until the law sin was in the world: but sin is not imputed when there is no law.', pt: 'Porque o pecado estava no mundo antes da lei; mas o pecado não é imputado não havendo lei.' },
      { v: 14, en: 'Nevertheless death reigned from Adam to Moses, even over them that had not sinned after the similitude of Adam\'s transgression, who is the figure of him that was to come.', pt: 'No entanto, a morte reinou desde Adão até Moisés, mesmo sobre os que não pecaram à semelhança da transgressão de Adão, o qual é a figura daquele que havia de vir.' },
      { v: 15, en: 'But not as the offence, so also is the free gift. For if through the offence of one many be dead, much more the grace of God, and the gift by grace, which is by one man, Jesus Christ, hath abounded unto many.', pt: 'Mas não sucedeu com o dom gratuito como com a ofensa; porque, se pela ofensa de um só morreram muitos, muito mais a graça de Deus e o dom pela graça de um só homem, Jesus Cristo, abundaram sobre muitos.' },
      { v: 16, en: 'And not as it was by one that sinned, so is the gift: for the judgment was by one to condemnation, but the free gift is of many offences unto justification.', pt: 'E não sucedeu com o dom como com aquilo que veio por um pecador; porque, com efeito, o juízo de um só resultou em condenação, mas o dom gratuito de muitas ofensas resultou em justificação.' },
      { v: 17, en: 'For if by one man\'s offence death reigned by one; much more they which receive abundance of grace and of the gift of righteousness shall reign in life by one, Jesus Christ.)', pt: 'Porque, se pela ofensa de um só a morte reinou por esse um, muito mais os que recebem a abundância da graça e do dom da justiça reinarão em vida por um só, Jesus Cristo.' },
      { v: 18, en: 'Therefore as by the offence of one judgment came upon all men to condemnation; even so by the righteousness of one the free gift came upon all men unto justification of life.', pt: 'Assim como, pois, por uma só ofensa veio o juízo sobre todos os homens para condenação, assim também por um só ato de justiça veio sobre todos os homens a justificação que dá vida.' },
      { v: 19, en: 'For as by one man\'s disobedience many were made sinners, so by the obedience of one shall many be made righteous.', pt: 'Porque, assim como pela desobediência de um só homem muitos foram constituídos pecadores, assim também pela obediência de um só muitos serão constituídos justos.' },
      { v: 20, en: 'Moreover the law entered, that the offence might abound. But where sin abounded, grace did much more abound:', pt: 'Sobrevieram também a lei para que a ofensa abundasse; mas onde o pecado abundou, superabundou a graça;' },
      { v: 21, en: 'That as sin hath reigned unto death, even so might grace reign through righteousness unto eternal life by Jesus Christ our Lord.', pt: 'para que, assim como o pecado reinou para a morte, assim também a graça reine pela justiça para a vida eterna por Jesus Cristo nosso Senhor.' },
    ],
    6: [
      { v: 1, en: 'What shall we say then? Shall we continue in sin, that grace may abound?', pt: 'Que diremos, pois? Permaneceremos no pecado para que a graça abunde?' },
      { v: 2, en: 'God forbid. How shall we, that are dead to sin, live any longer therein?', pt: 'De modo nenhum! Nós, que estamos mortos para o pecado, como viveremos ainda nele?' },
      { v: 3, en: 'Know ye not, that so many of us as were baptized into Jesus Christ were baptized into his death?', pt: 'Ou não sabeis que todos nós que fomos batizados em Cristo Jesus fomos batizados na sua morte?' },
      { v: 4, en: 'Therefore we are buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life.', pt: 'Fomos, pois, sepultados com ele pelo batismo na morte, para que, como Cristo ressuscitou dos mortos pela glória do Pai, assim também nós andemos em novidade de vida.' },
      { v: 5, en: 'For if we have been planted together in the likeness of his death, we shall be also in the likeness of his resurrection:', pt: 'Porque, se fomos unidos com ele na semelhança da sua morte, certamente o seremos também na de sua ressurreição;' },
      { v: 6, en: 'Knowing this, that our old man is crucified with him, that the body of sin might be destroyed, that henceforth we should not serve sin.', pt: 'sabendo que o nosso velho homem foi crucificado com ele, para que o corpo do pecado seja destruído, de modo que não sirvamos mais ao pecado.' },
      { v: 7, en: 'For he that is dead is freed from sin.', pt: 'Porque o que morreu está livre do pecado.' },
      { v: 8, en: 'Now if we be dead with Christ, we believe that we shall also live with him:', pt: 'Ora, se morremos com Cristo, cremos que também com ele viveremos,' },
      { v: 9, en: 'Knowing that Christ being raised from the dead dieth no more; death hath no more dominion over him.', pt: 'sabendo que Cristo, havendo ressuscitado dentre os mortos, não morre mais; a morte já não tem domínio sobre ele.' },
      { v: 10, en: 'For in that he died, he died unto sin once: but in that he liveth, he liveth unto God.', pt: 'Porque, quanto ao morrer, morreu para o pecado de uma vez por todas; mas quanto ao viver, vive para Deus.' },
      { v: 11, en: 'Likewise reckon ye also yourselves to be dead indeed unto sin, but alive unto God through Jesus Christ our Lord.', pt: 'Assim também vós considerai-vos mortos para o pecado, mas vivos para Deus em Cristo Jesus, nosso Senhor.' },
      { v: 12, en: 'Let not sin therefore reign in your mortal body, that ye should obey it in the lusts thereof.', pt: 'Portanto, não reine o pecado em vosso corpo mortal, de modo que obedeçais às suas concupiscências.' },
      { v: 13, en: 'Neither yield ye your members as instruments of unrighteousness unto sin: but yield yourselves unto God, as those that are alive from the dead, and your members as instruments of righteousness unto God.', pt: 'Nem apresenteis os vossos membros ao pecado como instrumentos de iniqüidade; mas apresentai-vos a Deus como os que de mortos voltaram à vida, e os vossos membros a Deus como instrumentos de justiça.' },
      { v: 14, en: 'For sin shall not have dominion over you: for ye are not under the law, but under grace.', pt: 'Porque o pecado não terá domínio sobre vós; pois não estais debaixo da lei, mas debaixo da graça.' },
      { v: 15, en: 'What then? shall we sin, because we are not under the law, but under grace? God forbid.', pt: 'Que, pois? Pecaremos porque não estamos debaixo da lei, mas debaixo da graça? De modo nenhum!' },
      { v: 16, en: 'Know ye not, that to whom ye yield yourselves servants to obey, his servants ye are to whom ye obey; whether of sin unto death, or of obedience unto righteousness?', pt: 'Não sabeis que, a quem vos apresentardes como escravos para obedecer, seus escravos sois, daquele a quem obedeceis, seja do pecado para a morte, seja da obediência para a justiça?' },
      { v: 17, en: 'But God be thanked, that ye were the servants of sin, but ye have obeyed from the heart that form of doctrine which was delivered you.', pt: 'Mas graças a Deus porque, embora fôsseis servos do pecado, obedecestes de coração à forma de doutrina que vos foi entregue.' },
      { v: 18, en: 'Being then made free from sin, ye became the servants of righteousness.', pt: 'E libertados do pecado, tornastes-vos servos da justiça.' },
      { v: 19, en: 'I speak after the manner of men because of the infirmity of your flesh: for as ye have yielded your members servants to uncleanness and to iniquity unto iniquity; even so now yield your members servants to righteousness unto holiness.', pt: 'Falo em termos humanos, por causa da fraqueza da vossa carne. Porque, assim como apresentastes os vossos membros como escravos à imundícia e à iniqüidade para a iniqüidade, assim também apresentai agora os vossos membros como escravos à justiça para a santificação.' },
      { v: 20, en: 'For when ye were the servants of sin, ye were free from righteousness.', pt: 'Porque, quando éreis servos do pecado, estáveis livres da justiça.' },
      { v: 21, en: 'What fruit had ye then in those things whereof ye are now ashamed? for the end of those things is death.', pt: 'Que fruto, pois, tínheis então naquelas coisas de que agora vos envergonhais? Porque o fim dessas coisas é a morte.' },
      { v: 22, en: 'But now being made free from sin, and become servants to God, ye have your fruit unto holiness, and the end everlasting life.', pt: 'Mas agora, libertados do pecado e feitos servos de Deus, tendes o vosso fruto para a santificação, e por fim a vida eterna.' },
      { v: 23, en: 'For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord.', pt: 'Porque o salário do pecado é a morte, mas o dom gratuito de Deus é a vida eterna em Cristo Jesus, nosso Senhor.' },
    ],
    7: [
      { v: 1, en: 'Know ye not, brethren, (for I speak to them that know the law,) how that the law hath dominion over a man as long as he liveth?', pt: 'Ou ignorais, irmãos (pois falo com os que conhecem a lei), que a lei tem domínio sobre o homem somente enquanto ele vive?' },
      { v: 2, en: 'For the woman which hath an husband is bound by the law to her husband so long as he liveth; but if the husband be dead, she is loosed from the law of her husband.', pt: 'Porque a mulher casada está ligada pela lei ao marido enquanto ele vive; mas, se o marido morrer, está livre da lei do marido.' },
      { v: 3, en: 'So then if, while her husband liveth, she be married to another man, she shall be called an adulteress: but if her husband be dead, she is free from that law; so that she is no adulteress, though she be married to another man.', pt: 'Portanto, se, enquanto o marido vive, ela se unir a outro homem, será chamada adúltera; mas se o marido morrer, estará livre da lei, de modo que não será adúltera se se unir a outro homem.' },
      { v: 4, en: 'Wherefore, my brethren, ye also are become dead to the law by the body of Christ; that ye should be married to another, even to him who is raised from the dead, that we should bring forth fruit unto God.', pt: 'Assim também, meus irmãos, fostes mortos para a lei pelo corpo de Cristo, para que vos unais a outro, a saber, àquele que ressuscitou dentre os mortos, para que produzamos fruto para Deus.' },
      { v: 5, en: 'For when we were in the flesh, the motions of sins, which were by the law, did work in our members to bring forth fruit unto death.', pt: 'Porque, quando estávamos na carne, as paixões dos pecados, que são pela lei, operavam em nossos membros para produzir fruto para a morte.' },
      { v: 6, en: 'But now we are delivered from the law, that being dead wherein we were held; that we should serve in newness of spirit, and not in the oldness of the letter.', pt: 'Mas agora estamos libertos da lei, por termos morrido para aquilo em que estávamos retidos, de modo que sirvamos em novidade de espírito, e não na velhice da letra.' },
      { v: 7, en: 'What shall we say then? Is the law sin? God forbid. Nay, I had not known sin, but by the law: for I had not known lust, except the law had said, Thou shalt not covet.', pt: 'Que diremos, pois? É a lei pecado? De modo nenhum! Mas eu não conheci o pecado senão pela lei; porque eu não conheceria a cobiça, se a lei não dissesse: Não cobiçarás.' },
      { v: 8, en: 'But sin, taking occasion by the commandment, wrought in me all manner of concupiscence. For without the law sin was dead.', pt: 'Mas o pecado, tomando ensejo pelo mandamento, produziu em mim toda a cobiça; porque sem lei o pecado está morto.' },
      { v: 9, en: 'For I was alive without the law once: but when the commandment came, sin revived, and I died.', pt: 'E eu vivia sem lei antigamente; mas, sobrevindo o mandamento, o pecado tornou a viver, e eu morri.' },
      { v: 10, en: 'And the commandment, which was ordained to life, I found to be unto death.', pt: 'E verifiquei que o mandamento que era para vida, esse mesmo me resultou em morte.' },
      { v: 11, en: 'For sin, taking occasion by the commandment, deceived me, and by it slew me.', pt: 'Porque o pecado, tomando ocasião pelo mandamento, me seduziu e por ele me matou.' },
      { v: 12, en: 'Wherefore the law is holy, and the commandment holy, and just, and good.', pt: 'Assim, a lei na verdade é santa, e o mandamento santo, justo e bom.' },
      { v: 13, en: 'Was then that which is good made death unto me? God forbid. But sin, that it might appear sin, working death in me by that which is good; that sin by the commandment might become exceeding sinful.', pt: 'Tornou-se, pois, para mim em morte o que era bom? De modo nenhum! Mas o pecado, para se manifestar como pecado, produziu em mim a morte mediante o bem; a fim de que o pecado viesse a ser em extremo pecaminoso pelo mandamento.' },
      { v: 14, en: 'For we know that the law is spiritual: but I am carnal, sold under sin.', pt: 'Porque sabemos que a lei é espiritual; mas eu sou carnal, vendido como escravo ao pecado.' },
      { v: 15, en: 'For that which I do I allow not: for what I would, that do I not; but what I hate, that do I.', pt: 'Porque o que faço, não o aprovo; pois não faço o que quero, mas o que odeio, isso faço.' },
      { v: 16, en: 'If then I do that which I would not, I consent unto the law that it is good.', pt: 'Ora, se faço o que não quero, reconheço que a lei é boa.' },
      { v: 17, en: 'Now then it is no more I that do it, but sin that dwelleth in me.', pt: 'Assim não sou mais eu que o faço, mas o pecado que habita em mim.' },
      { v: 18, en: 'For I know that in me (that is, in my flesh,) dwelleth no good thing: for to will is present with me; but how to perform that which is good I find not.', pt: 'Porque eu sei que em mim, isto é, na minha carne, não habita bem algum; porque o querer está presente em mim, mas o fazer o bem não o encontro.' },
      { v: 19, en: 'For the good that I would I do not: but the evil which I would not, that I do.', pt: 'Porque o bem que quero, não o faço; mas o mal que não quero, esse faço.' },
      { v: 20, en: 'Now if I do that I would not, it is no more I that do it, but sin that dwelleth in me.', pt: 'Ora, se faço o que não quero, não sou mais eu que o faço, mas o pecado que habita em mim.' },
      { v: 21, en: 'I find then a law, that, when I would do good, evil is present with me.', pt: 'Assim, verifico esta lei: que, querendo eu fazer o bem, o mal está presente em mim.' },
      { v: 22, en: 'For I delight in the law of God after the inward man:', pt: 'Porque, segundo o homem interior, tenho prazer na lei de Deus;' },
      { v: 23, en: 'But I see another law in my members, warring against the law of my mind, and bringing me into captivity to the law of sin which is in my members.', pt: 'mas vejo nos meus membros outra lei que batalha contra a lei da minha mente e me leva em cativeiro à lei do pecado que está nos meus membros.' },
      { v: 24, en: 'O wretched man that I am! who shall deliver me from the body of this death?', pt: 'Desgraçado homem que eu sou! Quem me livrará do corpo desta morte?' },
      { v: 25, en: 'I thank God through Jesus Christ our Lord. So then with the mind I myself serve the law of God; but with the flesh the law of sin.', pt: 'Graças a Deus por Jesus Cristo nosso Senhor! Assim, pois, eu mesmo, com a mente, sirvo à lei de Deus; mas com a carne, à lei do pecado.' },
    ],
    8: [
      { v: 1, en: 'There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit.', pt: 'Portanto, agora nenhuma condenação há para os que estão em Cristo Jesus, que não andam segundo a carne, mas segundo o Espírito.' },
      { v: 2, en: 'For the law of the Spirit of life in Christ Jesus hath made me free from the law of sin and death.', pt: 'Porque a lei do Espírito da vida em Cristo Jesus me livrou da lei do pecado e da morte.' },
      { v: 3, en: 'For what the law could not do, in that it was weak through the flesh, God sending his own Son in the likeness of sinful flesh, and for sin, condemned sin in the flesh:', pt: 'Porque o que era impossível à lei, visto como estava enfraquecida pela carne, Deus, enviando o seu próprio Filho em semelhança da carne do pecado e pelo pecado, condenou o pecado na carne;' },
      { v: 4, en: 'That the righteousness of the law might be fulfilled in us, who walk not after the flesh, but after the Spirit.', pt: 'para que o preceito da lei se cumprisse em nós, que não andamos segundo a carne, mas segundo o Espírito.' },
      { v: 5, en: 'For they that are after the flesh do mind the things of the flesh; but they that are after the Spirit the things of the Spirit.', pt: 'Porque os que são segundo a carne inclinam-se para as coisas da carne; mas os que são segundo o Espírito para as coisas do Espírito.' },
      { v: 6, en: 'For to be carnally minded is death; but to be spiritually minded is life and peace.', pt: 'Porque a inclinação da carne é morte; mas a inclinação do Espírito é vida e paz.' },
      { v: 7, en: 'Because the carnal mind is enmity against God: for it is not subject to the law of God, neither indeed can be.', pt: 'Porquanto a inclinação da carne é inimizade contra Deus, pois não é sujeita à lei de Deus, nem mesmo pode ser.' },
      { v: 8, en: 'So then they that are in the flesh cannot please God.', pt: 'Portanto, os que estão na carne não podem agradar a Deus.' },
      { v: 9, en: 'But ye are not in the flesh, but in the Spirit, if so be that the Spirit of God dwell in you. Now if any man have not the Spirit of Christ, he is none of his.', pt: 'Vós, porém, não estais na carne, mas no Espírito, se é que o Espírito de Deus habita em vós. Mas se alguém não tem o Espírito de Cristo, esse tal não é dele.' },
      { v: 10, en: 'And if Christ be in you, the body is dead because of sin; but the Spirit is life because of righteousness.', pt: 'Mas se Cristo está em vós, o corpo, na verdade, está morto por causa do pecado, mas o espírito é vida por causa da justiça.' },
      { v: 11, en: 'But if the Spirit of him that raised up Jesus from the dead dwell in you, he that raised up Christ from the dead shall also quicken your mortal bodies by his Spirit that dwelleth in you.', pt: 'E se o Espírito daquele que ressuscitou a Jesus dentre os mortos habita em vós, aquele que ressuscitou a Cristo dentre os mortos também vivificará os vossos corpos mortais pelo seu Espírito que em vós habita.' },
      { v: 12, en: 'Therefore, brethren, we are debtors, not to the flesh, to live after the flesh.', pt: 'Assim, pois, irmãos, somos devedores, não à carne, para vivermos segundo a carne;' },
      { v: 13, en: 'For if ye live after the flesh, ye shall die: but if ye through the Spirit do mortify the deeds of the body, ye shall live.', pt: 'porque, se viverdes segundo a carne, morrereis; mas se pelo Espírito mortificardes as obras do corpo, vivereis.' },
      { v: 14, en: 'For as many as are led by the Spirit of God, they are the sons of God.', pt: 'Porque todos os que são guiados pelo Espírito de Deus são filhos de Deus.' },
      { v: 15, en: 'For ye have not received the spirit of bondage again to fear; but ye have received the Spirit of adoption, whereby we cry, Abba, Father.', pt: 'Porque não recebestes o espírito de escravidão para estardes outra vez em temor, mas recebestes o espírito de adoção de filhos, pelo qual clamamos: Aba, Pai.' },
      { v: 16, en: 'The Spirit itself beareth witness with our spirit, that we are the children of God:', pt: 'O próprio Espírito testifica com o nosso espírito que somos filhos de Deus.' },
      { v: 17, en: 'And if children, then heirs; heirs of God, and joint-heirs with Christ; if so be that we suffer with him, that we may be also glorified together.', pt: 'E, se filhos, também herdeiros; herdeiros de Deus e co-herdeiros com Cristo; se é que com ele padecemos, para que também com ele sejamos glorificados.' },
      { v: 18, en: 'For I reckon that the sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us.', pt: 'Porque tenho para mim que os sofrimentos do tempo presente não são comparáveis com a glória que em nós há de ser revelada.' },
      { v: 19, en: 'For the earnest expectation of the creature waiteth for the manifestation of the sons of God.', pt: 'Porque a ardente expectação da criação aguarda a manifestação dos filhos de Deus.' },
      { v: 20, en: 'For the creature was made subject to vanity, not willingly, but by reason of him who hath subjected the same in hope,', pt: 'Pois a criação ficou sujeita à vaidade, não por sua própria vontade, mas por causa daquele que a sujeitou, na esperança' },
      { v: 21, en: 'Because the creature itself also shall be delivered from the bondage of corruption into the glorious liberty of the children of God.', pt: 'de que a própria criação será também libertada da escravidão da corrupção para a liberdade da glória dos filhos de Deus.' },
      { v: 22, en: 'For we know that the whole creation groaneth and travaileth in pain together until now.', pt: 'Porque sabemos que toda a criação está gemendo e suportando angústias até agora.' },
      { v: 23, en: 'And not only they, but ourselves also, which have the firstfruits of the Spirit, even we ourselves groan within ourselves, waiting for the adoption, to wit, the redemption of our body.', pt: 'E não somente ela, mas também nós mesmos, que temos as primícias do Espírito, gememos em nós mesmos, aguardando a adoção de filhos, a saber, a redenção do nosso corpo.' },
      { v: 24, en: 'For we are saved by hope: but hope that is seen is not hope: for what a man seeth, why doth he yet hope for?', pt: 'Porque em esperança fomos salvos. Ora, a esperança que se vê não é esperança; porque o que alguém vê, como o esperará?' },
      { v: 25, en: 'But if we hope for that we see not, then do we with patience wait for it.', pt: 'Mas, se esperamos o que não vemos, com paciência o aguardamos.' },
      { v: 26, en: 'Likewise the Spirit also helpeth our infirmities: for we know not what we should pray for as we ought: but the Spirit itself maketh intercession for us with groanings which cannot be uttered.', pt: 'E também o Espírito nos ajuda na nossa fraqueza; porque não sabemos orar como convém, mas o mesmo Espírito intercede por nós com gemidos inexprimíveis.' },
      { v: 27, en: 'And he that searcheth the hearts knoweth what is the mind of the Spirit, because he maketh intercession for the saints according to the will of God.', pt: 'E aquele que sonda os corações sabe qual é a intenção do Espírito, porque ele intercede pelos santos conforme a vontade de Deus.' },
      { v: 28, en: 'And we know that all things work together for good to them that love God, to them who are the called according to his purpose.', pt: 'E sabemos que todas as coisas contribuem juntamente para o bem daqueles que amam a Deus, daqueles que são chamados segundo o seu propósito.' },
      { v: 29, en: 'For whom he did foreknow, he also did predestinate to be conformed to the image of his Son, that he might be the firstborn among many brethren.', pt: 'Porque os que de antemão conheceu, também os predestinou para serem conformes à imagem de seu Filho, a fim de que ele seja o primogênito entre muitos irmãos.' },
      { v: 30, en: 'Moreover whom he did predestinate, them he also called: and whom he called, them he also justified: and whom he justified, them he also glorified.', pt: 'E aos que predestinou, a esses também chamou; e aos que chamou, a esses também justificou; e aos que justificou, a esses também glorificou.' },
      { v: 31, en: 'What shall we then say to these things? If God be for us, who can be against us?', pt: 'Que diremos, pois, a estas coisas? Se Deus é por nós, quem será contra nós?' },
      { v: 32, en: 'He that spared not his own Son, but delivered him up for us all, how shall he not with him also freely give us all things?', pt: 'Aquele que não poupou o seu próprio Filho, antes o entregou por todos nós, como não nos dará também com ele todas as coisas?' },
      { v: 33, en: 'Who shall lay any thing to the charge of God\'s elect? It is God that justifieth.', pt: 'Quem intentará acusação contra os eleitos de Deus? É Deus quem os justifica.' },
      { v: 34, en: 'Who is he that condemneth? It is Christ that died, yea rather, that is risen again, who is even at the right hand of God, who also maketh intercession for us.', pt: 'Quem os condenará? É Cristo Jesus quem morreu, mas, antes, ressuscitou, quem também está à direita de Deus, e intercede por nós.' },
      { v: 35, en: 'Who shall separate us from the love of Christ? shall tribulation, or distress, or persecution, or famine, or nakedness, or peril, or sword?', pt: 'Quem nos separará do amor de Cristo? A tribulação, ou a angústia, ou a perseguição, ou a fome, ou a nudez, ou o perigo, ou a espada?' },
      { v: 36, en: 'As it is written, For thy sake we are killed all the day long; we are accounted as sheep for the slaughter.', pt: 'Como está escrito: Por tua causa somos mortos todo o dia; fomos considerados como ovelhas para o matadouro.' },
      { v: 37, en: 'Nay, in all these things we are more than conquerors through him that loved us.', pt: 'Mas em todas estas coisas somos mais do que vencedores por meio daquele que nos amou.' },
      { v: 38, en: 'For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come,', pt: 'Porque estou persuadido de que nem a morte, nem a vida, nem os anjos, nem os principados, nem as potestades, nem o presente, nem o porvir,' },
      { v: 39, en: 'Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord.', pt: 'nem a altura, nem a profundidade, nem qualquer outra criatura nos poderá separar do amor de Deus, que está em Cristo Jesus, nosso Senhor.' },
    ],
    9: [
      { v: 1, en: 'I say the truth in Christ, I lie not, my conscience also bearing me witness in the Holy Ghost,', pt: 'Digo a verdade em Cristo, não minto, testemunhando-me também a minha consciência no Espírito Santo,' },
      { v: 2, en: 'That I have great heaviness and continual sorrow in my heart.', pt: 'que tenho grande tristeza e contínua dor no coração.' },
      { v: 3, en: 'For I could wish that myself were accursed from Christ for my brethren, my kinsmen according to the flesh:', pt: 'Porque eu mesmo desejaria ser anátema, separado de Cristo, por amor de meus irmãos, meus parentes segundo a carne;' },
      { v: 4, en: 'Who are Israelites; to whom pertaineth the adoption, and the glory, and the covenants, and the giving of the law, and the service of God, and the promises;', pt: 'que são israelitas, dos quais são a adoção de filhos, e a glória, e as alianças, e a promulgação da lei, e o culto, e as promessas;' },
      { v: 5, en: 'Whose are the fathers, and of whom as concerning the flesh Christ came, who is over all, God blessed for ever. Amen.', pt: 'dos quais são os pais, e dos quais, segundo a carne, descende Cristo, o qual é sobre tudo, Deus bendito eternamente. Amém.' },
      { v: 6, en: 'Not as though the word of God hath taken none effect. For they are not all Israel, which are of Israel:', pt: 'Não que a palavra de Deus haja falhado; porque nem todos os que descendem de Israel são israelitas;' },
      { v: 7, en: 'Neither, because they are the seed of Abraham, are they all children: but, In Isaac shall thy seed be called.', pt: 'nem por serem descendência de Abraão são todos filhos; mas: Em Isaque será chamada a tua descendência.' },
      { v: 8, en: 'That is, They which are the children of the flesh, these are not the children of God: but the children of the promise are counted for the seed.', pt: 'Isto é: Não são filhos de Deus os filhos segundo a carne, mas os filhos da promessa é que são considerados como descendência.' },
      { v: 9, en: 'For this is the word of promise, At this time will I come, and Sara shall have a son.', pt: 'Porque esta é a palavra da promessa: Voltarei por este tempo, e Sara terá um filho.' },
      { v: 10, en: 'And not only this; but when Rebecca also had conceived by one, even by our father Isaac;', pt: 'E não somente isso, mas também Rebeca, tendo concebido de um só, de Isaque, nosso pai,' },
      { v: 11, en: 'For the children being not yet born, neither having done any good or evil, that the purpose of God according to election might stand, not of works, but of him that calleth;)', pt: '(porque ainda não tendo eles nascido, nem tendo praticado bem ou mal, para que o propósito de Deus conforme a eleição permanecesse, não por obras, mas por aquele que chama),' },
      { v: 12, en: 'It was said unto her, The elder shall serve the younger.', pt: 'foi-lhe dito: O maior servirá o menor.' },
      { v: 13, en: 'As it is written, Jacob have I loved, but Esau have I hated.', pt: 'Como está escrito: Amei a Jacó, mas odiei a Esaú.' },
      { v: 14, en: 'What shall we say then? Is there unrighteousness with God? God forbid.', pt: 'Que diremos, pois? Há injustiça da parte de Deus? De modo nenhum!' },
      { v: 15, en: 'For he saith to Moses, I will have mercy on whom I will have mercy, and I will have compassion on whom I will have compassion.', pt: 'Porque ele diz a Moisés: Terei misericórdia de quem eu quiser ter misericórdia, e me compadecerei de quem eu quiser me compadecer.' },
      { v: 16, en: 'So then it is not of him that willeth, nor of him that runneth, but of God that sheweth mercy.', pt: 'Portanto, não depende de quem quer, nem de quem corre, mas de Deus que usa de misericórdia.' },
      { v: 17, en: 'For the scripture saith unto Pharaoh, Even for this same purpose have I raised thee up, that I might shew my power in thee, and that my name might be declared throughout all the earth.', pt: 'Porque a Escritura diz a Faraó: Para este mesmo fim te suscitei, para que eu mostre em ti o meu poder, e para que o meu nome seja anunciado em toda a terra.' },
      { v: 18, en: 'Therefore hath he mercy on whom he will have mercy, and whom he will he hardeneth.', pt: 'Assim, pois, usa de misericórdia com quem ele quer, e endurece a quem quer.' },
      { v: 19, en: 'Thou wilt say then unto me, Why doth he yet find fault? For who hath resisted his will?', pt: 'Dir-me-ás, pois: Por que se queixa ainda? Quem tem resistido à sua vontade?' },
      { v: 20, en: 'Nay but, O man, who art thou that repliest against God? Shall the thing formed say to him that formed it, Why hast thou made me thus?', pt: 'Mas, ó homem, quem és tu para discutires com Deus? Dirá porventura o vaso de barro ao que o formou: Por que me fizeste assim?' },
      { v: 21, en: 'Hath not the potter power over the clay, of the same lump to make one vessel unto honour, and another unto dishonour?', pt: 'Ou não tem o oleiro poder sobre o barro, para fazer do mesmo torrão um vaso para honra e outro para desonra?' },
      { v: 22, en: 'What if God, willing to shew his wrath, and to make his power known, endured with much longsuffering the vessels of wrath fitted to destruction:', pt: 'E se Deus, querendo mostrar a sua ira e dar a conhecer o seu poder, suportou com muita paciência os vasos de ira preparados para a destruição;' },
      { v: 23, en: 'And that he might make known the riches of his glory on the vessels of mercy, which he had afore prepared unto glory,', pt: 'e se isto foi para que desse a conhecer as riquezas da sua glória nos vasos de misericórdia que de antemão preparou para glória,' },
      { v: 24, en: 'Even us, whom he hath called, not of the Jews only, but also of the Gentiles?', pt: 'aos quais também chamou, a saber, a nós, não somente dentre os judeus, mas também dentre os gentios?' },
      { v: 25, en: 'As he saith also in Osee, I will call them my people, which were not my people; and her beloved, which was not beloved.', pt: 'Como também diz em Oséias: Ao que não era meu povo, chamarei meu povo; e à que não era amada, amada.' },
      { v: 26, en: 'And it shall come to pass, that in the place where it was said unto them, Ye are not my people; there shall they be called the children of the living God.', pt: 'E no lugar onde se lhes disse: Vós não sois meu povo, ali serão chamados filhos do Deus vivo.' },
      { v: 27, en: 'Esaias also crieth concerning Israel, Though the number of the children of Israel be as the sand of the sea, a remnant shall be saved:', pt: 'E Isaías exclama a respeito de Israel: Ainda que o número dos filhos de Israel seja como a areia do mar, um remanescente será salvo;' },
      { v: 28, en: 'For he will finish the work, and cut it short in righteousness: because a short work will the Lord make upon the earth.', pt: 'porque o Senhor cumprirá a sua palavra na terra, completa e prontamente.' },
      { v: 29, en: 'And as Esaias said before, Except the Lord of Sabaoth had left us a seed, we had been as Sodoma, and been made like unto Gomorrha.', pt: 'E como antes disse Isaías: Se o Senhor dos Exércitos não nos tivesse deixado descendência, teríamos sido como Sodoma e semelhantes a Gomorra.' },
      { v: 30, en: 'What shall we say then? That the Gentiles, which followed not after righteousness, have attained to righteousness, even the righteousness which is of faith.', pt: 'Que diremos, pois? Que os gentios, que não seguiam a justiça, alcançaram a justiça, mas a justiça que é pela fé;' },
      { v: 31, en: 'But Israel, which followed after the law of righteousness, hath not attained to the law of righteousness.', pt: 'mas Israel, seguindo a lei de justiça, não chegou à lei de justiça.' },
      { v: 32, en: 'Wherefore? Because they sought it not by faith, but as it were by the works of the law. For they stumbled at that stumblingstone;', pt: 'Por quê? Porque não a buscava pela fé, mas pelas obras da lei; tropecaram na pedra de tropeço,' },
      { v: 33, en: 'As it is written, Behold, I lay in Sion a stumblingstone and rock of offence: and whosoever believeth on him shall not be ashamed.', pt: 'como está escrito: Eis que ponho em Sião uma pedra de tropeço e rochedo de escândalo; e todo aquele que nele crer não será confundido.' },
    ],
    10: [
      { v: 1, en: 'Brethren, my heart\'s desire and prayer to God for Israel is, that they might be saved.', pt: 'Irmãos, o desejo do meu coração e a minha súplica a Deus por Israel é para que sejam salvos.' },
      { v: 2, en: 'For I bear them record that they have a zeal of God, but not according to knowledge.', pt: 'Porque lhes dou testemunho de que têm zelo de Deus, mas não segundo a ciência.' },
      { v: 3, en: 'For they being ignorant of God\'s righteousness, and going about to establish their own righteousness, have not submitted themselves unto the righteousness of God.', pt: 'Porque, ignorando a justiça de Deus e procurando estabelecer a sua própria justiça, não se sujeitaram à justiça de Deus.' },
      { v: 4, en: 'For Christ is the end of the law for righteousness to every one that believeth.', pt: 'Porque o fim da lei é Cristo, para justiça de todo aquele que crê.' },
      { v: 5, en: 'For Moses describeth the righteousness which is of the law, That the man which doeth those things shall live by them.', pt: 'Porque Moisés descreve a justiça que é pela lei: O homem que fizer estas coisas por elas viverá.' },
      { v: 6, en: 'But the righteousness which is of faith speaketh on this wise, Say not in thine heart, Who shall ascend into heaven? (that is, to bring Christ down from above:)', pt: 'Mas a justiça que é pela fé diz assim: Não digas no teu coração: Quem subirá ao céu? (isto é, para fazer descer a Cristo);' },
      { v: 7, en: 'Or, Who shall descend into the deep? (that is, to bring up Christ again from the dead.)', pt: 'ou: Quem descerá ao abismo? (isto é, para fazer subir a Cristo dentre os mortos).' },
      { v: 8, en: 'But what saith it? The word is nigh thee, even in thy mouth, and in thy heart: that is, the word of faith, which we preach;', pt: 'Mas que diz ela? A palavra está perto de ti, na tua boca e no teu coração; esta é a palavra da fé que pregamos:' },
      { v: 9, en: 'That if thou shalt confess with thy mouth the Lord Jesus, and shalt believe in thine heart that God hath raised him from the dead, thou shalt be saved.', pt: 'que, se confessares com a tua boca que Jesus é o Senhor, e creres no teu coração que Deus o ressuscitou dentre os mortos, serás salvo.' },
      { v: 10, en: 'For with the heart man believeth unto righteousness; and with the mouth confession is made unto salvation.', pt: 'Porque com o coração se crê para a justiça, e com a boca se faz confissão para a salvação.' },
      { v: 11, en: 'For the scripture saith, Whosoever believeth on him shall not be ashamed.', pt: 'Porque diz a Escritura: Todo aquele que nele crer não será confundido.' },
      { v: 12, en: 'For there is no difference between the Jew and the Greek: for the same Lord over all is rich unto all that call upon him.', pt: 'Porque não há distinção entre judeu e grego; porque o mesmo Senhor é Senhor de todos, rico para com todos os que o invocam.' },
      { v: 13, en: 'For whosoever shall call upon the name of the Lord shall be saved.', pt: 'Porque todo aquele que invocar o nome do Senhor será salvo.' },
      { v: 14, en: 'How then shall they call on him in whom they have not believed? and how shall they believe in him of whom they have not heard? and how shall they hear without a preacher?', pt: 'Como, pois, invocarão aquele em quem não creram? E como crerão naquele de quem não ouviram? E como ouvirão, se não há quem pregue?' },
      { v: 15, en: 'And how shall they preach, except they be sent? as it is written, How beautiful are the feet of them that preach the gospel of peace, and bring glad tidings of good things!', pt: 'E como pregarão, se não forem enviados? Como está escrito: Quão formosos são os pés dos que anunciam o evangelho da paz, dos que trazem boas novas!' },
      { v: 16, en: 'But they have not all obeyed the gospel. For Esaias saith, Lord, who hath believed our report?', pt: 'Mas nem todos obedeceram ao evangelho; porque Isaías diz: Senhor, quem creu ao nosso anúncio?' },
      { v: 17, en: 'So then faith cometh by hearing, and hearing by the word of God.', pt: 'De sorte que a fé vem pelo ouvir, e o ouvir pela palavra de Deus.' },
      { v: 18, en: 'But I say, Have they not heard? Yes verily, their sound went into all the earth, and their words unto the ends of the world.', pt: 'Mas digo: Porventura não ouviram? Sim, por certo: Por toda a terra saiu a voz deles, e as suas palavras chegaram até aos fins do mundo.' },
      { v: 19, en: 'But I say, Did not Israel know? First Moses saith, I will provoke you to jealousy by them that are no people, and by a foolish nation I will anger you.', pt: 'Mas digo: Não sabia Israel? Primeiro, Moisés diz: Eu vos provocarei ao ciúme com os que não são povo; com povo insensato vos farei irar.' },
      { v: 20, en: 'But Esaias is very bold, and saith, I was found of them that sought me not; I was made manifest unto them that asked not after me.', pt: 'Mas Isaías ousadamente diz: Fui achado pelos que não me buscavam; manifestei-me aos que por mim não perguntavam.' },
      { v: 21, en: 'But to Israel he saith, All day long I have stretched forth my hands unto a disobedient and gainsaying people.', pt: 'Mas a Israel diz: Todo o dia estendi as mãos a um povo desobediente e contraditador.' },
    ],
    11: [
      { v: 1, en: 'I say then, Hath God cast away his people? God forbid. For I also am an Israelite, of the seed of Abraham, of the tribe of Benjamin.', pt: 'Digo, pois: Rejeitou Deus o seu povo? De modo nenhum! Porque eu também sou israelita, da descendência de Abraão, da tribo de Benjamim.' },
      { v: 2, en: 'God hath not cast away his people which he foreknew. Wot ye not what the scripture saith of Elias? how he maketh intercession to God against Israel, saying,', pt: 'Deus não rejeitou o seu povo, que de antemão conheceu. Ou não sabeis o que diz a Escritura a respeito de Elias? Como ele intercede junto a Deus contra Israel, dizendo:' },
      { v: 3, en: 'Lord, they have killed thy prophets, and digged down thine altars; and I am left alone, and they seek my life.', pt: 'Senhor, mataram os teus profetas, derrubaram os teus altares; e só eu fiquei, e atentam contra a minha vida.' },
      { v: 4, en: 'But what saith the answer of God unto him? I have reserved to myself seven thousand men, who have not bowed the knee to the image of Baal.', pt: 'Mas que lhe diz a resposta divina? Guardei para mim sete mil homens, que não dobraram o joelho perante Baal.' },
      { v: 5, en: 'Even so then at this present time also there is a remnant according to the election of grace.', pt: 'Assim, pois, também no tempo presente há um remanescente segundo a eleição da graça.' },
      { v: 6, en: 'And if by grace, then is it no more of works: otherwise grace is no more grace. But if it be of works, then is it no more grace: otherwise work is no more work.', pt: 'Ora, se é pela graça, já não é pelas obras; de outro modo, a graça já não é graça. E se pelas obras, já não é pela graça; de outro modo, a obra já não é obra.' },
      { v: 7, en: 'What then? Israel hath not obtained that which he seeketh for; but the election hath obtained it, and the rest were blinded', pt: 'Que concluiremos, pois? Israel não obteve o que buscava; mas os eleitos o obtiveram, e os demais foram endurecidos,' },
      { v: 8, en: 'According as it is written, God hath given them the spirit of slumber, eyes that they should not see, and ears that they should not hear;) unto this day.', pt: 'como está escrito: Deus lhes deu espírito de entorpecimento, olhos para não verem e ouvidos para não ouvirem, até ao dia de hoje.' },
      { v: 9, en: 'And David saith, Let their table be made a snare, and a trap, and a stumblingblock, and a recompence unto them:', pt: 'E Davi diz: Torne-se-lhes a mesa em laço, e em armadilha, e em tropeço, e em paga;' },
      { v: 10, en: 'Let their eyes be darkened, that they may not see, and bow down their back alway.', pt: 'escureçam-se os seus olhos para que não vejam, e curva continuamente as suas costas.' },
      { v: 11, en: 'I say then, Have they stumbled that they should fall? God forbid: but rather through their fall salvation is come unto the Gentiles, for to provoke them to jealousy.', pt: 'Digo, pois: Porventura tropeçaram para que caíssem? De modo nenhum! Mas pela sua queda veio a salvação para os gentios, a fim de provocá-los ao ciúme.' },
      { v: 12, en: 'Now if the fall of them be the riches of the world, and the diminishing of them the riches of the Gentiles; how much more their fulness?', pt: 'Ora, se a queda deles é o enriquecimento do mundo, e o seu abatimento é o enriquecimento dos gentios, quanto mais a sua plenitude!' },
      { v: 13, en: 'For I speak to you Gentiles, inasmuch as I am the apostle of the Gentiles, I magnify mine office:', pt: 'Porque a vós outros, gentios, digo isto: na medida em que sou apóstolo dos gentios, glorifico o meu ministério,' },
      { v: 14, en: 'If by any means I may provoke to emulation them which are my flesh, and might save some of them.', pt: 'para ver se de algum modo provoco ao ciúme os meus co-nacionais e salvo alguns deles.' },
      { v: 15, en: 'For if the casting away of them be the reconciling of the world, what shall the receiving of them be, but life from the dead?', pt: 'Porque, se o repúdio deles é a reconciliação do mundo, o que será a sua aceitação, senão a vida dentre os mortos?' },
      { v: 16, en: 'For if the firstfruit be holy, the lump is also holy: and if the root be holy, so are the branches.', pt: 'Ora, se as primícias são santas, também o é a massa; e se a raiz é santa, também os ramos o são.' },
      { v: 17, en: 'And if some of the branches be broken off, and thou, being a wild olive tree, wert graffed in among them, and with them partakest of the root and fatness of the olive tree;', pt: 'Mas se alguns dos ramos foram quebrados, e tu, sendo oliveira brava, foste enxertado em lugar deles e te tornaste participante da raiz e da seiva da oliveira,' },
      { v: 18, en: 'Boast not against the branches. But if thou boast, thou bearest not the root, but the root thee.', pt: 'não te glories contra os ramos; e, se te glorias, sabe que não és tu que sustentas a raiz, mas a raiz que te sustenta.' },
      { v: 19, en: 'Thou wilt say then, The branches were broken off, that I might be graffed in.', pt: 'Dirás, pois: Os ramos foram quebrados para que eu fosse enxertado.' },
      { v: 20, en: 'Well; because of unbelief they were broken off, and thou standest by faith. Be not highminded, but fear:', pt: 'Muito bem! Por causa da incredulidade foram quebrados, e tu estás firme pela fé. Não te ensoberbeças, antes teme;' },
      { v: 21, en: 'For if God spared not the natural branches, take heed lest he also spare not thee.', pt: 'porque, se Deus não poupou os ramos naturais, também não te poupará a ti.' },
      { v: 22, en: 'Behold therefore the goodness and severity of God: on them which fell, severity; but toward thee, goodness, if thou continue in his goodness: otherwise thou also shalt be cut off.', pt: 'Considera, pois, a bondade e a severidade de Deus: para com os que caíram, severidade; mas para contigo, bondade de Deus, se permaneceres nessa bondade; de outro modo, também tu serás cortado.' },
      { v: 23, en: 'And they also, if they abide not still in unbelief, shall be graffed in: for God is able to graff them in again.', pt: 'E esses, se não permanecerem na incredulidade, serão enxertados; porque poderoso é Deus para os tornar a enxertar.' },
      { v: 24, en: 'For if thou wert cut out of the olive tree which is wild by nature, and wert graffed contrary to nature into a good olive tree: how much more shall these, which be the natural branches, be graffed into their own olive tree?', pt: 'Pois se tu foste cortado da que por natureza é oliveira brava e contra a natureza foste enxertado na boa oliveira, quanto mais esses, que são os ramos naturais, serão enxertados na sua própria oliveira?' },
      { v: 25, en: 'For I would not, brethren, that ye should be ignorant of this mystery, lest ye should be wise in your own conceits; that blindness in part is happened to Israel, until the fulness of the Gentiles be come in.', pt: 'Porque não quero, irmãos, que ignoreis este mistério para que não sejais sábios em vosso próprio conceito: que o endurecimento em parte aconteceu em Israel, até que haja entrado a plenitude dos gentios.' },
      { v: 26, en: 'And so all Israel shall be saved: as it is written, There shall come out of Sion the Deliverer, and shall turn away ungodliness from Jacob:', pt: 'E assim todo o Israel será salvo; como está escrito: De Sião virá o Libertador, e desviará de Jacó as impiedades;' },
      { v: 27, en: 'For this is my covenant unto them, when I shall take away their sins.', pt: 'e esta será a minha aliança com eles, quando eu tirar os seus pecados.' },
      { v: 28, en: 'As concerning the gospel, they are enemies for your sakes: but as touching the election, they are beloved for the fathers\' sakes.', pt: 'Quanto ao evangelho, são inimigos por amor de vós; mas quanto à eleição, são amados por amor dos pais.' },
      { v: 29, en: 'For the gifts and calling of God are without repentance.', pt: 'Porque os dons e a vocação de Deus são sem arrependimento.' },
      { v: 30, en: 'For as ye in times past have not believed God, yet have now obtained mercy through their unbelief:', pt: 'Porque, assim como vós também noutro tempo fostes desobedientes a Deus, mas agora alcançastes misericórdia pela incredulidade deles,' },
      { v: 31, en: 'Even so have these also now not believed, that through your mercy they also may obtain mercy.', pt: 'assim também estes agora foram desobedientes, para que, pela misericórdia que vós alcançastes, também eles alcancem misericórdia.' },
      { v: 32, en: 'For God hath concluded them all in unbelief, that he might have mercy upon all.', pt: 'Porque Deus encerrou todos na desobediência, para usar de misericórdia para com todos.' },
      { v: 33, en: 'O the depth of the riches both of the wisdom and knowledge of God! how unsearchable are his judgments, and his ways past finding out!', pt: 'Ó profundidade das riquezas, tanto da sabedoria como do conhecimento de Deus! Quão insondáveis são os seus juízos, e quão inescrutáveis os seus caminhos!' },
      { v: 34, en: 'For who hath known the mind of the Lord? or who hath been his counsellor?', pt: 'Porque quem conheceu a mente do Senhor? Ou quem foi o seu conselheiro?' },
      { v: 35, en: 'Or who hath first given to him, and it shall be recompensed unto him again?', pt: 'Ou quem lhe deu primeiro, para que lhe seja recompensado?' },
      { v: 36, en: 'For of him, and through him, and to him, are all things: to whom be glory for ever. Amen.', pt: 'Porque dele e por ele e para ele são todas as coisas. A ele, pois, a glória eternamente. Amém.' },
    ],
    12: [
      { v: 1, en: 'I beseech you therefore, brethren, by the mercies of God, that ye present your bodies a living sacrifice, holy, acceptable unto God, which is your reasonable service.', pt: 'Rogo-vos, pois, irmãos, pela compaixão de Deus, que apresenteis os vossos corpos como sacrifício vivo, santo e agradável a Deus, que é o vosso culto racional.' },
      { v: 2, en: 'And be not conformed to this world: but be ye transformed by the renewing of your mind, that ye may prove what is that good, and acceptable, and perfect, will of God.', pt: 'E não vos conformeis com este século, mas transformai-vos pela renovação da vossa mente, para que experimenteis qual seja a boa, agradável e perfeita vontade de Deus.' },
      { v: 3, en: 'For I say, through the grace given unto me, to every man that is among you, not to think of himself more highly than he ought to think; but to think soberly, according as God hath dealt to every man the measure of faith.', pt: 'Porque pela graça que me foi dada digo a cada um dentre vós que não pense de si mesmo além do que convém; antes, pense com moderação, conforme a medida da fé que Deus distribuiu a cada um.' },
      { v: 4, en: 'For as we have many members in one body, and all members have not the same office:', pt: 'Porque, assim como em um corpo temos muitos membros, e todos os membros não têm a mesma função,' },
      { v: 5, en: 'So we, being many, are one body in Christ, and every one members one of another.', pt: 'assim também nós, sendo muitos, somos um só corpo em Cristo, mas individualmente membros uns dos outros.' },
      { v: 6, en: 'Having then gifts differing according to the grace that is given to us, whether prophecy, let us prophesy according to the proportion of faith;', pt: 'De modo que, tendo diferentes dons segundo a graça que nos foi dada, se o de profecia, seja exercido segundo a proporção da fé;' },
      { v: 7, en: 'Or ministry, let us wait on our ministering: or he that teacheth, on teaching;', pt: 'se o de ministério, seja exercido no ministério; se o de ensinar, no ensino;' },
      { v: 8, en: 'Or he that exhorteth, on exhortation: he that giveth, let him do it with simplicity; he that ruleth, with diligence; he that sheweth mercy, with cheerfulness.', pt: 'se o de exortar, na exortação; o que dá, faça-o com liberalidade; o que preside, com diligência; o que exercita misericórdia, com alegria.' },
      { v: 9, en: 'Let love be without dissimulation. Abhor that which is evil; cleave to that which is good.', pt: 'O amor seja sem fingimento. Aborrecei o mal e apegai-vos ao bem.' },
      { v: 10, en: 'Be kindly affectioned one to another with brotherly love; in honour preferring one another;', pt: 'Amai-vos cordialmente uns aos outros com amor fraternal; na honra, preferindo-vos uns aos outros;' },
      { v: 11, en: 'Not slothful in business; fervent in spirit; serving the Lord;', pt: 'no zelo, não vagarosos; ardentes em espírito; servindo ao Senhor;' },
      { v: 12, en: 'Rejoicing in hope; patient in tribulation; continuing instant in prayer;', pt: 'alegres na esperança; pacientes na tribulação; perseverantes na oração;' },
      { v: 13, en: 'Distributing to the necessity of saints; given to hospitality.', pt: 'comunicando para as necessidades dos santos; praticando a hospitalidade.' },
      { v: 14, en: 'Bless them which persecute you: bless, and curse not.', pt: 'Abençoai os que vos perseguem; abençoai, e não amaldiçoeis.' },
      { v: 15, en: 'Rejoice with them that do rejoice, and weep with them that weep.', pt: 'Alegrai-vos com os que se alegram; chorai com os que choram.' },
      { v: 16, en: 'Be of the same mind one toward another. Mind not high things, but condescend to men of low estate. Be not wise in your own conceits.', pt: 'Sede unânimes entre vós; não ambicioneis coisas altas, mas dai-vos ao que é humilde; não sejais sábios em vossas próprias opiniões.' },
      { v: 17, en: 'Recompense to no man evil for evil. Provide things honest in the sight of all men.', pt: 'A ninguém retribuais mal por mal; procurai as coisas honestas diante de todos os homens.' },
      { v: 18, en: 'If it be possible, as much as lieth in you, live peaceably with all men.', pt: 'Se possível for, quanto depender de vós, tende paz com todos os homens.' },
      { v: 19, en: 'Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord.', pt: 'Não vos vingueis a vós mesmos, amados, mas dai lugar à ira; porque está escrito: Minha é a vingança; eu darei a recompensa, diz o Senhor.' },
      { v: 20, en: 'Therefore if thine enemy hunger, feed him; if he thirst, give him drink: for in so doing thou shalt heap coals of fire on his head.', pt: 'Portanto, se o teu inimigo tiver fome, dá-lhe de comer; se tiver sede, dá-lhe de beber; porque, fazendo isso, amontoarás brasas de fogo sobre a sua cabeça.' },
      { v: 21, en: 'Be not overcome of evil, but overcome evil with good.', pt: 'Não sejas vencido do mal, mas vence o mal com o bem.' },
    ],
    13: [
      { v: 1, en: 'Let every soul be subject unto the higher powers. For there is no power but of God: the powers that be are ordained of God.', pt: 'Toda alma se sujeite às autoridades superiores; porque não há autoridade que não venha de Deus; e as que existem foram instituídas por Deus.' },
      { v: 2, en: 'Whosoever therefore resisteth the power, resisteth the ordinance of God: and they that resist shall receive to themselves damnation.', pt: 'De modo que aquele que resiste à autoridade resiste à ordenação de Deus; e os que resistem trarão sobre si mesmos condenação.' },
      { v: 3, en: 'For rulers are not a terror to good works, but to the evil. Wilt thou then not be afraid of the power? do that which is good, and thou shalt have praise of the same:', pt: 'Porque os magistrados não são terror para as boas obras, mas para as más. Queres tu não temer a autoridade? Faz o bem, e terás o seu louvor.' },
      { v: 4, en: 'For he is the minister of God to thee for good. But if thou do that which is evil, be afraid; for he beareth not the sword in vain: for he is the minister of God, a revenger to execute wrath upon him that doeth evil.', pt: 'porque ela é ministro de Deus para teu bem. Mas, se fizeres o mal, teme; porque não traz em vão a espada; pois é ministro de Deus, vingador para castigar o que pratica o mal.' },
      { v: 5, en: 'Wherefore ye must needs be subject, not only for wrath, but also for conscience sake.', pt: 'Por isso é necessário que estejais sujeitos, não somente por causa da ira, mas também por causa da consciência.' },
      { v: 6, en: 'For for this cause pay ye tribute also: for they are God\'s ministers, attending continually upon this very thing.', pt: 'Pois é por isso que também pagais tributos; porque são ministros de Deus, atendendo sempre a isso mesmo.' },
      { v: 7, en: 'Render therefore to all their dues: tribute to whom tribute is due; custom to whom custom; fear to whom fear; honour to whom honour.', pt: 'Portanto, dai a todos o que é devido: a quem tributo, tributo; a quem imposto, imposto; a quem temor, temor; a quem honra, honra.' },
      { v: 8, en: 'Owe no man any thing, but to love one another: for he that loveth another hath fulfilled the law.', pt: 'A ninguém devais coisa alguma, a não ser o amor mútuo; porque quem ama ao próximo tem cumprido a lei.' },
      { v: 9, en: 'For this, Thou shalt not commit adultery, Thou shalt not kill, Thou shalt not steal, Thou shalt not bear false witness, Thou shalt not covet; and if there be any other commandment, it is briefly comprehended in this saying, namely, Thou shalt love thy neighbour as thyself.', pt: 'Porque isto: Não adulterarás, não matarás, não furtarás, não cobiçarás, e qualquer outro mandamento, tudo se resume nesta palavra: Amarás o teu próximo como a ti mesmo.' },
      { v: 10, en: 'Love worketh no ill to his neighbour: therefore love is the fulfilling of the law.', pt: 'O amor não faz mal ao próximo. De sorte que o cumprimento da lei é o amor.' },
      { v: 11, en: 'And that, knowing the time, that now it is high time to awake out of sleep: for now is our salvation nearer than when we believed.', pt: 'E isso, conhecendo o tempo, que é já hora de despertarmos do sono; porque a nossa salvação está agora mais perto do que quando cremos.' },
      { v: 12, en: 'The night is far spent, the day is at hand: let us therefore cast off the works of darkness, and let us put on the armour of light.', pt: 'A noite já passou; o dia está próximo. Rejeitemos, pois, as obras das trevas e revistamo-nos das armas da luz.' },
      { v: 13, en: 'Let us walk honestly, as in the day; not in rioting and drunkenness, not in chambering and wantonness, not in strife and envying.', pt: 'Andemos com decência, como de dia; não em orgias nem embriagueiras, não em impudicícias nem libertinagens, não em contendas nem ciúmes.' },
      { v: 14, en: 'But put ye on the Lord Jesus Christ, and make not provision for the flesh, to fulfil the lusts thereof.', pt: 'Mas revesti-vos do Senhor Jesus Cristo e não tenhais cuidado da carne em suas concupiscências.' },
    ],
    14: [
      { v: 1, en: 'Him that is weak in the faith receive ye, but not to doubtful disputations.', pt: 'Recebei o que é fraco na fé, mas não para julgar-lhe os pensamentos.' },
      { v: 2, en: 'For one believeth that he may eat all things: another, who is weak, eateth herbs.', pt: 'Porque um crê que pode comer de tudo; mas o que é fraco come legumes.' },
      { v: 3, en: 'Let not him that eateth despise him that eateth not; and let not him which eateth not judge him that eateth: for God hath received him.', pt: 'O que come não despreze o que não come; e o que não come não julgue o que come; porque Deus o recebeu.' },
      { v: 4, en: 'Who art thou that judgest another man\'s servant? to his own master he standeth or falleth. Yea, he shall be holden up: for God is able to make him stand.', pt: 'Quem és tu que julgas o servo alheio? Ele está em pé ou cai para o seu próprio senhor. Mas ficará em pé; porque poderoso é o Senhor para o sustentar.' },
      { v: 5, en: 'One man esteemeth one day above another: another esteemeth every day alike. Let every man be fully persuaded in his own mind.', pt: 'Um distingue um dia de outro dia; para outro, porém, todos os dias são iguais. Cada um esteja plenamente persuadido no seu próprio entendimento.' },
      { v: 6, en: 'He that regardeth the day, regardeth it unto the Lord; and he that regardeth not the day, to the Lord he doth not regard it. He that eateth, eateth to the Lord, for he giveth God thanks; and he that eateth not, to the Lord he eateth not, and giveth God thanks.', pt: 'O que faz caso de certo dia, faz-o para o Senhor; e o que não faz caso de algum dia, para o Senhor não faz caso. O que come, para o Senhor come; porque dá graças a Deus; e o que não come, para o Senhor não come, e também dá graças a Deus.' },
      { v: 7, en: 'For none of us liveth to himself, and no man dieth to himself.', pt: 'Porque nenhum de nós vive para si mesmo, e nenhum morre para si mesmo.' },
      { v: 8, en: 'For whether we live, we live unto the Lord; and whether we die, we die unto the Lord: whether we live therefore, or die, we are the Lord\'s.', pt: 'Pois, se vivemos, para o Senhor vivemos; se morremos, para o Senhor morremos. Quer vivamos, pois, quer morramos, somos do Senhor.' },
      { v: 9, en: 'For to this end Christ both died, and rose, and revived, that he might be Lord both of the dead and living.', pt: 'Porque para isto mesmo morreu Cristo e ressuscitou, para ser Senhor, tanto dos mortos como dos vivos.' },
      { v: 10, en: 'But why dost thou judge thy brother? or why dost thou set at nought thy brother? for we shall all stand before the judgment seat of Christ.', pt: 'Mas tu, por que julgas teu irmão? Ou tu também, por que desprezas teu irmão? Pois todos compareceremos ante o tribunal de Deus.' },
      { v: 11, en: 'For it is written, As I live, saith the Lord, every knee shall bow to me, and every tongue shall confess to God.', pt: 'Porque está escrito: Vivo eu, diz o Senhor, que todo joelho se dobrará a mim, e toda língua louvará a Deus.' },
      { v: 12, en: 'So then every one of us shall give account of himself to God.', pt: 'De modo que cada um de nós prestará conta de si mesmo a Deus.' },
      { v: 13, en: 'Let us not therefore judge one another any more: but judge this rather, that no man put a stumblingblock or an occasion to fall in his brother\'s way.', pt: 'Assim, pois, não nos julguemos mais uns aos outros; antes, julgai antes isso: não pordes tropeço ou escândalo diante de vosso irmão.' },
      { v: 14, en: 'I know, and am persuaded by the Lord Jesus, that there is nothing unclean of itself: but to him that esteemeth any thing to be unclean, to him it is unclean.', pt: 'Eu sei, e estou persuadido no Senhor Jesus, que nada é imundo em si mesmo; mas para quem considera alguma coisa imunda, para esse é imunda.' },
      { v: 15, en: 'But if thy brother be grieved with thy meat, now walkest thou not charitably. Destroy not him with thy meat, for whom Christ died.', pt: 'Pois se por causa do teu alimento teu irmão fica magoado, já não andas segundo o amor. Não destruas com o teu alimento aquele por quem Cristo morreu.' },
      { v: 16, en: 'Let not then your good be evil spoken of:', pt: 'Que o vosso bem não seja, portanto, blasfemado;' },
      { v: 17, en: 'For the kingdom of God is not meat and drink; but righteousness, and peace, and joy in the Holy Ghost.', pt: 'porque o reino de Deus não é comida nem bebida, mas justiça, e paz, e alegria no Espírito Santo.' },
      { v: 18, en: 'For he that in these things serveth Christ is acceptable to God, and approved of men.', pt: 'Porque quem nestas coisas serve a Cristo é agradável a Deus e aprovado pelos homens.' },
      { v: 19, en: 'Let us therefore follow after the things which make for peace, and things wherewith one may edify another.', pt: 'Assim, pois, sigamos as coisas que são para a paz e para a mútua edificação.' },
      { v: 20, en: 'For meat destroy not the work of God. All things indeed are pure; but it is evil for that man who eateth with offence.', pt: 'Não destruas por causa do alimento a obra de Deus. Na verdade, todas as coisas são puras; mas é mau para o homem comer com escândalo.' },
      { v: 21, en: 'It is good neither to eat flesh, nor to drink wine, nor any thing whereby thy brother stumbleth, or is offended, or is made weak.', pt: 'Bom é não comer carne, nem beber vinho, nem fazer qualquer coisa em que teu irmão tropece, ou se escandalize, ou se enfraqueça.' },
      { v: 22, en: 'Hast thou faith? have it to thyself before God. Happy is he that condemneth not himself in that thing which he alloweth.', pt: 'Tu tens fé? Tem-na para contigo diante de Deus. Bem-aventurado aquele que não se condena no que aprova.' },
      { v: 23, en: 'And he that doubteth is damned if he eat, because he eateth not of faith: for whatsoever is not of faith is sin.', pt: 'Mas aquele que tem dúvidas, se comer, fica condenado, porque não age pela fé. E tudo o que não é de fé é pecado.' },
    ],
    15: [
      { v: 1, en: 'We then that are strong ought to bear the infirmities of the weak, and not to please ourselves.', pt: 'Nós, pois, que somos fortes, devemos suportar as fraquezas dos fracos e não agradar a nós mesmos.' },
      { v: 2, en: 'Let every one of us please his neighbour for his good to edification.', pt: 'Cada um de nós procure agradar ao próximo no que é bom, para edificação.' },
      { v: 3, en: 'For even Christ pleased not himself; but, as it is written, The reproaches of them that reproached thee fell on me.', pt: 'Porque também Cristo não agradou a si mesmo; mas, como está escrito: Os vitupérios dos que te vituperam caíram sobre mim.' },
      { v: 4, en: 'For whatsoever things were written aforetime were written for our learning, that we through patience and comfort of the scriptures might have hope.', pt: 'Porque tudo o que dantes foi escrito, para nosso ensino foi escrito, para que, pela paciência e pela consolação das Escrituras, tenhamos esperança.' },
      { v: 5, en: 'Now the God of patience and consolation grant you to be likeminded one toward another according to Christ Jesus:', pt: 'Ora, o Deus da paciência e da consolação vos conceda que tenhais uns para com os outros o mesmo sentimento, segundo Cristo Jesus;' },
      { v: 6, en: 'That ye may with one mind and one mouth glorify God, even the Father of our Lord Jesus Christ.', pt: 'para que concordemente, a uma voz, glorifiqueis ao Deus e Pai de nosso Senhor Jesus Cristo.' },
      { v: 7, en: 'Wherefore receive ye one another, as Christ also received us to the glory of God.', pt: 'Portanto, recebei-vos uns aos outros, como também Cristo nos recebeu para a glória de Deus.' },
      { v: 8, en: 'Now I say that Jesus Christ was a minister of the circumcision for the truth of God, to confirm the promises made unto the fathers:', pt: 'Porque digo que Jesus Cristo foi ministro da circuncisão em prol da verdade de Deus, para confirmar as promessas feitas aos pais,' },
      { v: 9, en: 'And that the Gentiles might glorify God for his mercy; as it is written, For this cause I will confess to thee among the Gentiles, and sing unto thy name.', pt: 'e para que os gentios glorifiquem a Deus pela sua misericórdia, como está escrito: Por isso eu te louvarei entre os gentios e cantarei ao teu nome.' },
      { v: 10, en: 'And again he saith, Rejoice, ye Gentiles, with his people.', pt: 'E outra vez diz: Alegrai-vos, gentios, com o seu povo.' },
      { v: 11, en: 'And again, Praise the Lord, all ye Gentiles; and laud him, all ye people.', pt: 'E outra vez: Louvai ao Senhor, todos os gentios, e celebrai-o todos os povos.' },
      { v: 12, en: 'And again, Esaias saith, There shall be a root of Jesse, and he that shall rise to reign over the Gentiles; in him shall the Gentiles trust.', pt: 'E outra vez Isaías diz: Haverá uma raiz de Jessé, e um que se levantará para governar os gentios; nele os gentios esperarão.' },
      { v: 13, en: 'Now the God of hope fill you with all joy and peace in believing, that ye may abound in hope, through the power of the Holy Ghost.', pt: 'Ora, o Deus de esperança vos encha de todo o gozo e paz no crer, para que abundeis em esperança pelo poder do Espírito Santo.' },
      { v: 14, en: 'And I myself also am persuaded of you, my brethren, that ye also are full of goodness, filled with all knowledge, able also to admonish one another.', pt: 'Mas, irmãos, estou eu mesmo também persuadido de vós de que sois cheios de bondade, repletos de todo o conhecimento, podendo também admoestas-vos uns aos outros.' },
      { v: 15, en: 'Nevertheless, brethren, I have written the more boldly unto you in some sort, as putting you in mind, because of the grace that is given to me of God,', pt: 'Mas vos escrevi em parte mais ousadamente, como para vos recordar, pela graça que me foi dada de Deus' },
      { v: 16, en: 'That I should be the minister of Jesus Christ to the Gentiles, ministering the gospel of God, that the offering up of the Gentiles might be acceptable, being sanctified by the Holy Ghost.', pt: 'para ser ministro de Jesus Cristo para os gentios, ministrando o evangelho de Deus, a fim de que a oferta dos gentios seja aceitável, santificada pelo Espírito Santo.' },
      { v: 17, en: 'I have therefore whereof I may glory through Jesus Christ in those things which pertain to God.', pt: 'Tenho, pois, de que me gloriar em Cristo Jesus nas coisas que pertencem a Deus.' },
      { v: 18, en: 'For I will not dare to speak of any of those things which Christ hath not wrought by me, to make the Gentiles obedient, by word and deed,', pt: 'Porque não ousarei falar de coisa alguma que Cristo não haja efetuado por meu intermédio para a obediência dos gentios, em palavra e obra,' },
      { v: 19, en: 'Through mighty signs and wonders, by the power of the Spirit of God; so that from Jerusalem, and round about unto Illyricum, I have fully preached the gospel of Christ.', pt: 'com o poder de sinais e prodígios, com o poder do Espírito de Deus; de modo que, desde Jerusalém, e em roda até ao Ilírico, tenho amplamente pregado o evangelho de Cristo.' },
      { v: 20, en: 'Yea, so have I strived to preach the gospel, not where Christ was named, lest I should build upon another man\'s foundation:', pt: 'E assim me esforcei por pregar o evangelho, não onde Cristo já fosse conhecido, para não edificar sobre fundamento alheio,' },
      { v: 21, en: 'But as it is written, To whom he was not spoken of, they shall see: and they that have not heard shall understand.', pt: 'mas, como está escrito: Aqueles a quem não foi anunciado o verão; e os que não ouviram entenderão.' },
      { v: 22, en: 'For which cause also I have been much hindered from coming to you.', pt: 'Por isso, também tenho sido muito impedido de ir ter convosco.' },
      { v: 23, en: 'But now having no more place in these parts, and having a great desire these many years to come unto you;', pt: 'Mas agora, não tendo mais lugar nestas regiões, e tendo grande desejo de ir a vós outros já há muitos anos,' },
      { v: 24, en: 'Whensoever I take my journey into Spain, I will come to you: for I trust to see you in my journey, and to be brought on my way thitherward by you, if first I be somewhat filled with your company.', pt: 'quando for à Espanha, irei ter convosco; porque espero ver-vos passando, e ser encaminhado por vós para lá, depois de me ter primeiro satisfeito algo com a vossa companhia.' },
      { v: 25, en: 'But now I go unto Jerusalem to minister unto the saints.', pt: 'Mas agora vou a Jerusalém, a fim de ministrar aos santos.' },
      { v: 26, en: 'For it hath pleased them of Macedonia and Achaia to make a certain contribution for the poor saints which are at Jerusalem.', pt: 'Porque aprouve à Macedônia e à Acaia fazer uma contribuição para os pobres dentre os santos que estão em Jerusalém.' },
      { v: 27, en: 'It hath pleased them verily; and their debtors they are. For if the Gentiles have been made partakers of their spiritual things, their duty is also to minister unto them in carnal things.', pt: 'Aprouve-lhes isso; e, de fato, são seus devedores. Porque, se os gentios foram feitos participantes dos bens espirituais deles, devem também ministrar-lhes nos temporais.' },
      { v: 28, en: 'When therefore I have performed this, and have sealed to them this fruit, I will come by you into Spain.', pt: 'Quando, pois, tiver acabado isto e lhes tiver seguramente entregue este fruto, partirei para a Espanha, passando por vós.' },
      { v: 29, en: 'And I am sure that, when I come unto you, I shall come in the fulness of the blessing of the gospel of Christ.', pt: 'E sei que, quando for ter convosco, irei na plenitude da bênção do evangelho de Cristo.' },
      { v: 30, en: 'Now I beseech you, brethren, for the Lord Jesus Christ\'s sake, and for the love of the Spirit, that ye strive together with me in your prayers to God for me;', pt: 'Ora, rogo-vos, irmãos, por nosso Senhor Jesus Cristo e pelo amor do Espírito, que combatais juntamente comigo em orações a Deus por mim,' },
      { v: 31, en: 'That I may be delivered from them that do not believe in Judaea; and that my service which I have for Jerusalem may be accepted of the saints;', pt: 'para que seja liberto dos que são desobedientes na Judéia, e que o meu ministério para Jerusalém seja bem aceito pelos santos,' },
      { v: 32, en: 'That I may come unto you with joy by the will of God, and may with you be refreshed.', pt: 'para que, com alegria, vá ter convosco, pela vontade de Deus, e me refrigere juntamente convosco.' },
      { v: 33, en: 'Now the God of peace be with you all. Amen.', pt: 'Ora, o Deus da paz seja com todos vós. Amém.' },
    ],
    16: [
      { v: 1, en: 'I commend unto you Phebe our sister, which is a servant of the church which is at Cenchrea:', pt: 'Recomendo-vos a Febe, nossa irmã, que é diaconisa da igreja em Cencreia,' },
      { v: 2, en: 'That ye receive her in the Lord, as becometh saints, and that ye assist her in whatsoever business she hath need of you: for she hath been a succourer of many, and of myself also.', pt: 'para que a recebais no Senhor, como convém aos santos, e a assistais em qualquer negócio em que ela precise de vós; porque ela tem sido protetora de muitos, e de mim mesmo.' },
      { v: 3, en: 'Greet Priscilla and Aquila my helpers in Christ Jesus:', pt: 'Saudai a Priscila e Áquila, meus colaboradores em Cristo Jesus,' },
      { v: 4, en: 'Who have for my life laid down their own necks: unto whom not only I give thanks, but also all the churches of the Gentiles.', pt: 'que arriscaram as suas próprias vidas por mim; aos quais não somente eu dou graças, mas também todas as igrejas dos gentios.' },
      { v: 5, en: 'Likewise greet the church that is in their house. Salute my wellbeloved Epaenetus, who is the firstfruits of Achaia unto Christ.', pt: 'Saudai também a igreja que está em sua casa. Saudai a Epêneto, meu amado, que foi o primícias da Acaia para Cristo.' },
      { v: 6, en: 'Greet Mary, who bestowed much labour on us.', pt: 'Saudai a Maria, que muito trabalhou por vós.' },
      { v: 7, en: 'Salute Andronicus and Junia, my kinsmen, and my fellowprisoners, who are of note among the apostles, who also were in Christ before me.', pt: 'Saudai a Andrônico e a Júnias, meus parentes e meus companheiros de prisão, que são bem conceituados entre os apóstolos, os quais também foram em Cristo antes de mim.' },
      { v: 8, en: 'Greet Amplias my beloved in the Lord.', pt: 'Saudai a Amplias, meu amado no Senhor.' },
      { v: 9, en: 'Salute Urbane, our helper in Christ, and Stachys my beloved.', pt: 'Saudai a Urbano, nosso cooperador em Cristo, e a Estáquis, meu amado.' },
      { v: 10, en: 'Salute Apelles approved in Christ. Salute them which are of Aristobulus\' household.', pt: 'Saudai a Apeles, aprovado em Cristo. Saudai os da casa de Aristóbulo.' },
      { v: 11, en: 'Salute Herodion my kinsman. Greet them that be of the household of Narcissus, which are in the Lord.', pt: 'Saudai a Herodião, meu parente. Saudai os da casa de Narciso, os que estão no Senhor.' },
      { v: 12, en: 'Salute Tryphena and Tryphosa, who labour in the Lord. Salute the beloved Persis, which laboured much in the Lord.', pt: 'Saudai a Trifena e a Trifosa, que trabalham no Senhor. Saudai a amada Pérside, que muito trabalhou no Senhor.' },
      { v: 13, en: 'Salute Rufus chosen in the Lord, and his mother and mine.', pt: 'Saudai a Rufo, escolhido no Senhor, e a sua mãe, que é também minha.' },
      { v: 14, en: 'Salute Asyncritus, Phlegon, Hermas, Patrobas, Hermes, and the brethren which are with them.', pt: 'Saudai a Assíncrito, a Flegonte, a Hermes, a Pátrobas, a Hermas, e aos irmãos que estão com eles.' },
      { v: 15, en: 'Salute Philologus, and Julia, Nereus, and his sister, and Olympas, and all the saints which are with them.', pt: 'Saudai a Filólogo e a Júlia, a Nereu e a sua irmã, e a Olimpas, e a todos os santos que estão com eles.' },
      { v: 16, en: 'Salute one another with an holy kiss. The churches of Christ salute you.', pt: 'Saudai-vos uns aos outros com ósculo santo. As igrejas de Cristo vos saúdam.' },
      { v: 17, en: 'Now I beseech you, brethren, mark them which cause divisions and offences contrary to the doctrine which ye have learned; and avoid them.', pt: 'Ora, rogo-vos, irmãos, que noteis os que promovem divisões e escândalos contra a doutrina que aprendestes, e que deles vos desvieis.' },
      { v: 18, en: 'For they that are such serve not our Lord Jesus Christ, but their own belly; and by good words and fair speeches deceive the hearts of the simple.', pt: 'Porque os tais não servem a nosso Senhor Jesus Cristo, mas ao seu próprio ventre; e com suaves palavras e lisonjeiras enganam os corações dos simples.' },
      { v: 19, en: 'For your obedience is come abroad unto all men. I am glad therefore on your behalf: but yet I would have you wise unto that which is good, and simple concerning evil.', pt: 'Porque a vossa obediência é conhecida de todos. Por isso me alegro a respeito de vós; mas quero que sejais sábios para o bem, e simples para o mal.' },
      { v: 20, en: 'And the God of peace shall bruise Satan under your feet shortly. The grace of our Lord Jesus Christ be with you. Amen.', pt: 'E o Deus de paz em breve esmagará Satanás debaixo de vossos pés. A graça de nosso Senhor Jesus Cristo seja convosco. Amém.' },
      { v: 21, en: 'Timotheus my workfellow, and Lucius, and Jason, and Sosipater, my kinsmen, salute you.', pt: 'Saúda-vos Timóteo, meu cooperador, bem como Lúcio, Jasão e Sosípatro, meus parentes.' },
      { v: 22, en: 'I Tertius, who wrote this epistle, salute you in the Lord.', pt: 'Eu, Tércio, que escrevi esta epístola, vos saúdo no Senhor.' },
      { v: 23, en: 'Gaius mine host, and of the whole church, saluteth you. Erastus the chamberlain of the city saluteth you, and Quartus a brother.', pt: 'Saúda-vos Gaio, que me hospeda a mim e a toda a igreja. Saúda-vos Erasto, tesoureiro da cidade, e o irmão Quarto.' },
      { v: 24, en: 'The grace of our Lord Jesus Christ be with you all. Amen.', pt: 'A graça de nosso Senhor Jesus Cristo seja com todos vós. Amém.' },
      { v: 25, en: 'Now to him that is of power to stablish you according to my gospel, and the preaching of Jesus Christ, according to the revelation of the mystery, which was kept secret since the world began,', pt: 'Ora, àquele que é poderoso para vos confirmar segundo o meu evangelho e a pregação de Jesus Cristo, segundo a revelação do mistério que desde tempos eternos esteve oculto,' },
      { v: 26, en: 'But now is made manifest, and by the scriptures of the prophets, according to the commandment of the everlasting God, made known to all nations for the obedience of faith:', pt: 'mas que agora se manifestou, e pelas Escrituras dos profetas, segundo o mandamento do Deus eterno, foi dado a conhecer a todas as nações, para a obediência da fé;' },
      { v: 27, en: 'To God only wise, be glory through Jesus Christ for ever. Amen.', pt: 'ao único Deus sábio, seja dada glória por Jesus Cristo eternamente. Amém.' },
    ],
  },
};
